"background:#fff0f4;\">🎬</div>\n    <div><div style=\"font-size:.84rem;font-weight:700;\">Publicar Vídeo</div><div style=\"font-size:.7rem;color:var(--t3);\">No feed da comunidade</div></div>\n  </div>\n  <div class=\"pub-item\" onclick=\"openCreateChannel()\">\n    <div class=\"pub-icon\" style=\"background:#eef3ff;\">📡</div>\n    <div><div style=\"font-size:.84rem;font-weight:700;\">Criar Canal</div><div style=\"font-size:.7rem;color:var(--t3);\">Canal com @capdrawn.com</div></div>\n  </div>\n  <div class=\"pub-item\" onclick=\"closePublishMenu();document.getElementById('chatSection').scrollIntoView({behavior:'smooth'})\">\n    <div class=\"pub-icon\" style=\"background:#f0fdf4;\">💬</div>\n    <div><div style=\"font-size:.84rem;font-weight:700;\">Comentar</div><div style=\"font-size:.7rem;color:var(--t3);\">No chat da comunidade</div></div>\n  </div>\n</div>\n\n<button id=\"fabBtn\" onclick=\"openPublishMenu()\" style=\"display:none;\">\n  <svg width=\"22\" height=\"22\" viewBox=\"0 0 22 22\" fill=\"none\"><path d=\"M11 5v12M5 11h12\" stroke=\"white\" stroke-width=\"2.4\" stroke-linecap=\"round\"/></svg>\n</button>\n\n<nav id=\"bottomNav\">\n  <button class=\"bnav-btn active\" id=\"bnavHome\" onclick=\"goHome()\">\n    <svg width=\"22\" height=\"22\" viewBox=\"0 0 22 22\" fill=\"none\"><path d=\"M3 9.5L11 3l8 6.5V19a1 1 0 01-1 1H14v-5H8v5H4a1 1 0 01-1-1V9.5z\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/></svg>\n    <span>Início</span>\n  </button>\n  <button class=\"bnav-btn\" id=\"bnavVideos\" onclick=\"openVideoFeed()\">\n    <svg width=\"22\" height=\"22\" viewBox=\"0 0 22 22\" fill=\"none\"><rect x=\"2\" y=\"4\" width=\"14\" height=\"14\" rx=\"2\" stroke=\"currentColor\" stroke-width=\"1.8\"/><path d=\"M16 9l4-3v10l-4-3V9z\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/></svg>\n    <span>Vídeos</span>\n  </button>\n  <button class=\"bnav-plus\" onclick=\"APP.me?openPublishMenu():openLogin()\">\n    <svg width=\"22\" height=\"22\" viewBox=\"0 0 22 22\" fill=\"none\"><path d=\"M11 5v12M5 11h12\" stroke=\"white\" stroke-width=\"2.4\" stroke-linecap=\"round\"/></svg>\n  </button>\n  <button class=\"bnav-btn\" id=\"bnavComm\" onclick=\"document.getElementById('chatSection').scrollIntoView({behavior:'smooth'});setActiveNav('bnavComm')\">\n    <svg width=\"22\" height=\"22\" viewBox=\"0 0 22 22\" fill=\"none\"><path d=\"M4 4h14v10H12l-4 4v-4H4V4z\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/></svg>\n    <span>Chat</span>\n  </button>\n  <button class=\"bnav-btn\" id=\"bnavMe\" onclick=\"APP.me?openProfile(APP.me.handle):openLogin()\">\n    <svg width=\"22\" height=\"22\" viewBox=\"0 0 22 22\" fill=\"none\"><circle cx=\"11\" cy=\"8\" r=\"3.5\" stroke=\"currentColor\" stroke-width=\"1.8\"/><path d=\"M3.5 19c0-3.866 3.358-7 7.5-7s7.5 3.134 7.5 7\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\"/></svg>\n    <span>Perfil</span>\n  </button>\n</nav>\n\n<!-- LOGIN MODAL -->\n<div class=\"overlay\" id=\"loginModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>Entrar no CapDrawn</h3><button class=\"modal-x\" onclick=\"closeModal('loginModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"frow\"><label>Email ou usuário</label><input class=\"finp\" id=\"liEmail\" placeholder=\"usuario ou usuario@capdrawn.com\" autocomplete=\"email\"/></div>\n      <div class=\"frow\"><label>Senha</label><input class=\"finp\" type=\"password\" id=\"liPass\" placeholder=\"••••••••\" autocomplete=\"current-password\" onkeydown=\"if(event.key==='Enter')doLogin()\"/></div>\n      <p id=\"loginErr\" style=\"font-size:.75rem;color:var(--red);display:none;margin-top:4px;\"></p>\n      <p style=\"font-size:.72rem;color:var(--t3);margin-top:6px;\">Não tem conta? <a onclick=\"openRegister()\" style=\"color:var(--blue);cursor:pointer;font-weight:600;\">Criar conta →</a></p>\n    </div>\n    <div class=\"modal-foot\">\n      <button class=\"btn-out\" onclick=\"closeModal('loginModal')\">Cancelar</button>\n      <button class=\"btn-main\" id=\"loginBtn\" onclick=\"doLogin()\">Entrar →</button>\n    </div>\n  </div>\n</div>\n\n<!-- REGISTER MODAL -->\n<div class=\"overlay\" id=\"regModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>Criar conta CapDrawn</h3><button class=\"modal-x\" onclick=\"closeModal('regModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"av-pick\">\n        <div class=\"av-prev\" id=\"regAvPrev\" style=\"background:var(--blue);font-size:1.3rem;\">C</div>\n        <div>\n          <button class=\"btn-out\" style=\"padding:6px 12px;font-size:.78rem;\" onclick=\"document.getElementById('avUpload').click()\">📷 Foto</button>\n          <input type=\"file\" id=\"avUpload\" accept=\"image/*\" style=\"display:none\" onchange=\"prevAvatar(this,'regAvPrev')\"/>\n          <div class=\"col-row\">\n            <div class=\"col-dot active\" style=\"background:#0052e0;\" data-c=\"#0052e0\" onclick=\"setAvCol(this,'regAvPrev')\"></div>\n            <div class=\"col-dot\" style=\"background:#e0245e;\" data-c=\"#e0245e\" onclick=\"setAvCol(this,'regAvPrev')\"></div>\n            <div class=\"col-dot\" style=\"background:#00b86b;\" data-c=\"#00b86b\" onclick=\"setAvCol(this,'regAvPrev')\"></div>\n            <div class=\"col-dot\" style=\"background:#ff7a00;\" data-c=\"#ff7a00\" onclick=\"setAvCol(this,'regAvPrev')\"></div>\n            <div class=\"col-dot\" style=\"background:#7c3aed;\" data-c=\"#7c3aed\" onclick=\"setAvCol(this,'regAvPrev')\"></div>\n            <div class=\"col-dot\" style=\"background:#0b0b14;\" data-c=\"#0b0b14\" onclick=\"setAvCol(this,'regAvPrev')\"></div>\n          </div>\n        </div>\n      </div>\n      <div class=\"frow\"><label>Nome *</label><input class=\"finp\" id=\"regName\" placeholder=\"Ex: João Silva\" oninput=\"updateRegInit()\"/></div>\n      <div class=\"frow\"><label>@ Usuário *</label><input class=\"finp\" id=\"regHandle\" placeholder=\"joaosilva\"/></div>\n      <div class=\"frow\"><label>Email <span style=\"font-size:.7rem;color:var(--t3);\">(vira nome@capdrawn.com)</span></label>\n        <div style=\"display:flex;align-items:center;border:1.5px solid var(--border);border-radius:10px;overflow:hidden;background:var(--w);\">\n          <input class=\"finp\" id=\"regEmail\" placeholder=\"seunome\" style=\"border:none;border-radius:0;flex:1;margin:0;\" oninput=\"updateEmailPreview()\"/>\n          <span style=\"padding:0 10px;color:var(--t3);font-size:.78rem;white-space:nowrap;background:var(--bg);\">@capdrawn.com</span>\n        </div>\n        <small id=\"emailPreview\" style=\"color:var(--blue);font-size:.7rem;margin-top:2px;display:block;\"></small>\n      </div>\n      <div class=\"frow\"><label>Senha *</label><input class=\"finp\" type=\"password\" id=\"regPass\" placeholder=\"Mínimo 6 caracteres\" autocomplete=\"new-password\"/></div>\n      <div class=\"frow\"><label>Descrição do canal</label><textarea class=\"finp\" id=\"regDesc\" placeholder=\"Fale sobre você…\" style=\"min-height:60px;resize:none;\"></textarea></div>\n      <div class=\"frow\">\n        <label>🎓 Área</label>\n        <div class=\"badge-sel\" id=\"badgeSel\">\n          <div class=\"bo\" data-b=\"memes\" onclick=\"selBadge(this)\"><span style=\"display:inline-flex;align-items:center;gap:4px;padding:3px 10px;border-radius:20px;font-size:.72rem;font-weight:700;background:#fff3e0;color:#e65100;\">💀 Memes</span></div>\n          <div class=\"bo\" data-b=\"gaming\" onclick=\"selBadge(this)\"><span style=\"display:inline-flex;align-items:center;gap:4px;padding:3px 10px;border-radius:20px;font-size:.72rem;font-weight:700;background:#e8fff5;color:#00a060;\">🎮 Gaming</span></div>\n          <div class=\"bo\" data-b=\"criador\" onclick=\"selBadge(this)\"><span style=\"display:inline-flex;align-items:center;gap:4px;padding:3px 10px;border-radius:20px;font-size:.72rem;font-weight:700;background:#eef3ff;color:#0052e0;\">🎬 Criador</span></div>\n          <div class=\"bo\" data-b=\"musica\" onclick=\"selBadge(this)\"><span style=\"display:inline-flex;align-items:center;gap:4px;padding:3px 10px;border-radius:20px;font-size:.72rem;font-weight:700;background:#f3e5f5;color:#6a1b9a;\">🎵 Música</span></div>\n        </div>\n      </div>\n      <p id=\"regErr\" style=\"font-size:.75rem;color:var(--red);display:none;margin-top:4px;\"></p>\n      <p style=\"font-size:.72rem;color:var(--t3);margin-top:6px;\">⚠️ O @ não pode ser mudado depois de criado.</p>\n    </div>\n    <div class=\"modal-foot\">\n      <button class=\"btn-out\" onclick=\"closeModal('regModal')\">Cancelar</button>\n      <button class=\"btn-main\" id=\"regBtn\" onclick=\"createAccount()\">Criar conta →</button>\n    </div>\n  </div>\n</div>\n\n<!-- PROFILE EDIT MODAL -->\n<div class=\"overlay\" id=\"profileModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>Editar Perfil</h3><button class=\"modal-x\" onclick=\"closeModal('profileModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"av-pick\">\n        <div class=\"av-prev\" id=\"editAvPrev\">?</div>\n        <div>\n          <button class=\"btn-out\" style=\"padding:6px 12px;font-size:.78rem;\" onclick=\"document.getElementById('editAvFile').click()\">📷 Trocar foto</button>\n          <input type=\"file\" id=\"editAvFile\" accept=\"image/*\" style=\"display:none\" onchange=\"prevAvatar(this,'editAvPrev')\"/>\n        </div>\n      </div>\n      <div class=\"frow\"><label>Nome</label><input class=\"finp\" id=\"editName\"/></div>\n      <div class=\"frow\"><label>Descrição</label><textarea class=\"finp\" id=\"editDesc\" style=\"min-height:60px;resize:none;\"></textarea></div>\n    </div>\n    <div class=\"modal-foot\">\n      <button class=\"btn-out\" style=\"color:var(--red);\" onclick=\"logout()\">Sair</button>\n      <button class=\"btn-main\" onclick=\"saveProfile()\">Salvar →</button>\n    </div>\n  </div>\n</div>\n\n<!-- VIDEO COMMENTS MODAL -->\n<div class=\"overlay\" id=\"videoCommentsModal\">\n  <div class=\"modal\" style=\"max-height:85vh;\">\n    <div class=\"modal-head\" style=\"border-bottom:1px solid var(--border);\">\n      <h3 id=\"vcModalTitle\">Comentários</h3>\n      <button class=\"modal-x\" onclick=\"closeModal('videoCommentsModal')\">✕</button>\n    </div>\n    <div style=\"padding:10px 16px;max-height:55vh;overflow-y:auto;\" id=\"videoCommentsList\">\n      <div style=\"text-align:center;padding:20px;color:var(--t3);font-size:.82rem;\">Carregando comentários…</div>\n    </div>\n    <div id=\"vcSaveStatus\" class=\"vcmt-status\" style=\"margin:0 16px 8px;\"></div>\n    <div style=\"padding:10px 16px 16px;border-top:1px solid var(--border);display:flex;gap:8px;align-items:center;\">\n      <div class=\"c-av\" id=\"vcCompAv\" style=\"width:30px;height:30px;font-size:.72rem;flex-shrink:0;\">?</div>\n      <div style=\"flex:1;position:relative;\">\n        <input type=\"text\" id=\"vcInput\" placeholder=\"Comentar… (Enter para enviar)\" style=\"width:100%;padding:8px 12px;border:1.5px solid var(--border);border-radius:22px;font-size:.82rem;outline:none;font-family:inherit;\" oninput=\"onVcMentInput(this)\" onkeydown=\"if(event.key==='Enter')sendVidComment()\"/>\n        <div id=\"vcMentDrop\" class=\"ment-drop\" style=\"bottom:100%;top:auto;\"></div>\n      </div>\n      <button onclick=\"sendVidComment()\" style=\"padding:8px 14px;background:var(--t);color:#fff;border:none;border-radius:22px;font-size:.78rem;font-weight:700;cursor:pointer;white-space:nowrap;\">Enviar</button>\n    </div>\n  </div>\n</div>\n\n<!-- UPLOAD VIDEO MODAL -->\n<div class=\"overlay\" id=\"uploadModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>Publicar Vídeo</h3><button class=\"modal-x\" onclick=\"closeModal('uploadModal');clearVideo()\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"upload-drop\" id=\"uploadDrop\" onclick=\"document.getElementById('vidFile').click()\" ondragover=\"onDragOver(event)\" ondragleave=\"onDragLeave(event)\" ondrop=\"onDrop(event)\">\n        <div class=\"upload-drop-icon\">🎬</div>\n        <div class=\"upload-drop-text\">Clique ou arraste um vídeo</div>\n        <div class=\"upload-drop-sub\">MP4, MOV, WEBM — máx. 200 MB</div>\n      </div>\n      <input type=\"file\" id=\"vidFile\" accept=\"video/*\" style=\"display:none\" onchange=\"handleVideoFile(this.files[0])\"/>\n      <div class=\"upload-preview\" id=\"uploadPreview\">\n        <video id=\"uploadVidEl\" muted playsinline style=\"width:100%;height:100%;object-fit:cover;\"></video>\n        <button class=\"upload-preview-close\" onclick=\"clearVideo()\">✕</button>\n      </div>\n      <div class=\"upload-analysis\" id=\"uploadAnalysis\"></div>\n      <div id=\"uploadFields\" style=\"display:none;flex-direction:column;gap:8px;margin-bottom:12px;\">\n        <input class=\"finp\" id=\"vidCaption\" placeholder=\"Legenda do vídeo…\"/>\n        <div style=\"display:flex;align-items:center;gap:10px;padding:8px 0;\">\n          <label style=\"font-size:.75rem;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.05em;\">Privacidade</label>\n          <div style=\"display:flex;gap:6px;\">\n            <div class=\"dist-opt sel\" id=\"privPublic\" onclick=\"selPrivacy('public')\" style=\"min-width:80px;padding:6px 10px;\">\n              <div style=\"font-size:.9rem;\">🌍</div>\n              <div class=\"dist-opt-name\" style=\"font-size:.7rem;\">Público</div>\n            </div>\n            <div class=\"dist-opt\" id=\"privPrivate\" onclick=\"selPrivacy('private')\" style=\"min-width:80px;padding:6px 10px;\">\n              <div style=\"font-size:.9rem;\">🔒</div>\n              <div class=\"dist-opt-name\" style=\"font-size:.7rem;\">Privado</div>\n            </div>\n          </div>\n        </div>\n      </div>\n      <!-- Distribuição -->\n      <div id=\"uploadDistSection\" style=\"display:none;\">\n        <div class=\"frow\"><label>Como publicar?</label></div>\n        <div class=\"dist-opts\">\n          <div class=\"dist-opt sel\" id=\"doptProfile\" onclick=\"selDist('profile')\">\n            <div class=\"dist-opt-icon\">👤</div>\n            <div class=\"dist-opt-name\">Meu Perfil</div>\n            <div class=\"dist-opt-desc\">Aparece no seu canal</div>\n          </div>\n          <div class=\"dist-opt\" id=\"doptBots\" onclick=\"selDist('bots')\">\n            <div class=\"dist-opt-icon\">🤖</div>\n            <div class=\"dist-opt-name\">Via Bot</div>\n            <div class=\"dist-opt-desc\">Bot publica, você é dono</div>\n          </div>\n          <div class=\"dist-opt\" id=\"doptBoth\" onclick=\"selDist('both')\">\n            <div class=\"dist-opt-icon\">🚀</div>\n            <div class=\"dist-opt-name\">Ambos</div>\n            <div class=\"dist-opt-desc\">Perfil + distribuição bot</div>\n          </div>\n        </div>\n        <!-- Seletor de bot -->\n        <div class=\"bot-picker\" id=\"botPickerDiv\">\n          <label>Escolha o bot distribuidor</label>\n          <select class=\"bot-select\" id=\"botPickerSelect\">\n            <option value=\"\">Bot aleatório</option>\n          </select>\n        </div>\n      </div>\n      <button class=\"btn-main\" id=\"uploadSubmitBtn\" style=\"display:none;width:100%;justify-content:center;\" onclick=\"submitVideo()\">Publicar →</button>\n    </div>\n  </div>\n</div>\n\n<!-- VIP MODAL -->\n<div class=\"overlay pay-modal\" id=\"vipModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\" style=\"background:#0b0b14;border-radius:20px 20px 0 0;\"><h3 style=\"color:#f0c040;\">⭐ VIP CapDrawn</h3><button class=\"modal-x\" onclick=\"closeModal('vipModal')\" style=\"background:rgba(255,255,255,.1);color:#fff;\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"pay-opt\" id=\"po1\" onclick=\"selPay(1)\">\n        <div class=\"pay-opt-ico\">🎵</div>\n        <div><div class=\"pay-opt-name\">Siga no TikTok</div><div class=\"pay-opt-desc\">Siga @capdrawnn e receba o código VIP Pro</div><span class=\"pay-opt-badge\">VIP Pro</span></div>\n      </div>\n      <div id=\"tikPayBox\" class=\"tiktok-pay-box\">\n        <div style=\"font-size:.75rem;color:rgba(255,255,255,.5);margin-bottom:6px;\">1. <a href=\"https://lite.tiktok.com/ref/capdrawnn\" target=\"_blank\" style=\"color:#f0c040;\">Siga no TikTok →</a></div>\n        <div style=\"font-size:.75rem;color:rgba(255,255,255,.5);margin-bottom:6px;\">2. Cole o código no chat do TikTok:</div>\n        <div class=\"tikcode\" id=\"tikCode\">CAPDRAWNN-XXXXXX</div>\n        <button onclick=\"copyCode()\" style=\"width:100%;padding:8px;background:rgba(240,192,64,.12);border:1px solid rgba(240,192,64,.3);border-radius:8px;color:#f0c040;font-size:.78rem;font-weight:700;cursor:pointer;\">📋 Copiar código</button>\n        <button onclick=\"confirmVipPayment()\" style=\"width:100%;margin-top:8px;padding:10px;background:linear-gradient(135deg,#b8860b,#f0c040);border:none;border-radius:8px;color:#fff;font-size:.84rem;font-weight:700;cursor:pointer;\">✅ Já segui — ativar VIP Pro</button>\n      </div>\n      <div class=\"pay-opt\" id=\"po2\" onclick=\"selPay(2)\">\n        <div class=\"pay-opt-ico\">▶</div>\n        <div><div class=\"pay-opt-name\">Inscreva no YouTube</div><div class=\"pay-opt-desc\">Inscreva-se em @capdrawnn e receba VIP Ultra + Verificado</div><span class=\"pay-opt-badge\">VIP Ultra ✓</span></div>\n      </div>\n      <div id=\"ytSubBox\" class=\"ytSubBox\">\n        <div style=\"font-size:.75rem;color:rgba(255,255,255,.5);margin-bottom:8px;\"><a href=\"https://youtube.com/@capdrawnn\" target=\"_blank\" style=\"color:#f0c040;\">Inscreva-se no YouTube →</a></div>\n        <button onclick=\"confirmVipYT()\" style=\"width:100%;padding:10px;background:linear-gradient(135deg,#c00,#ff4444);border:none;border-radius:8px;color:#fff;font-size:.84rem;font-weight:700;cursor:pointer;\">✅ Já me inscrevi — ativar VIP Ultra</button>\n      </div>\n    </div>\n  </div>\n</div>\n\n<!-- SUPERCHAT MODAL -->\n<div class=\"overlay\" id=\"scModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>💛 Super Chat</h3><button class=\"modal-x\" onclick=\"closeModal('scModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"frow\"><label>Mensagem</label><input class=\"finp\" id=\"scMsg\" placeholder=\"Sua mensagem de destaque…\"/></div>\n      <div class=\"frow\"><label>Valor</label>\n        <select class=\"finp\" id=\"scVal\"><option value=\"5\">R$ 5</option><option value=\"20\">R$ 20</option><option value=\"50\">R$ 50</option></select>\n      </div>\n    </div>\n    <div class=\"modal-foot\">\n      <button class=\"btn-out\" onclick=\"closeModal('scModal')\">Cancelar</button>\n      <button class=\"btn-main\" onclick=\"sendSuperChat()\">Enviar Super Chat →</button>\n    </div>\n  </div>\n</div>\n\n<!-- REPORT MODAL -->\n<div class=\"overlay\" id=\"reportModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>Denunciar vídeo</h3><button class=\"modal-x\" onclick=\"closeModal('reportModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"report-opt\" id=\"ropt1\" onclick=\"selReport('inappropriate')\">\n        <div class=\"report-opt-radio\" id=\"rrad1\"></div>\n        <div><strong style=\"font-size:.84rem;\">Conteúdo impróprio</strong><div style=\"font-size:.72rem;color:var(--t3);margin-top:2px;\">Violência, nudez, discurso de ódio ou spam</div></div>\n      </div>\n      <div class=\"report-opt\" id=\"ropt2\" onclick=\"selReport('copyright')\">\n        <div class=\"report-opt-radio\" id=\"rrad2\"></div>\n        <div><strong style=\"font-size:.84rem;\">Direitos autorais</strong><div style=\"font-size:.72rem;color:var(--t3);margin-top:2px;\">Meu conteúdo foi usado sem permissão</div></div>\n      </div>\n      <div class=\"report-sub\" id=\"reportCopyrightSub\">\n        <div class=\"report-sub-opt\" id=\"rsubOwner\" onclick=\"selCopyrightType('owner')\"><div class=\"report-opt-radio\" id=\"rsubOwnerDot\" style=\"width:14px;height:14px;border:2px solid var(--border2);border-radius:50%;flex-shrink:0;\"></div>Sou o dono do conteúdo</div>\n        <div class=\"report-sub-opt\" id=\"rsubThird\" onclick=\"selCopyrightType('third')\"><div class=\"report-opt-radio\" id=\"rsubThirdDot\" style=\"width:14px;height:14px;border:2px solid var(--border2);border-radius:50%;flex-shrink:0;\"></div>Estou reportando em nome de outro</div>\n      </div>\n      <div id=\"reportConfirmBox\" style=\"display:none;margin-top:10px;padding:10px 13px;background:#fff0f2;border:1px solid #fda4af;border-radius:9px;font-size:.78rem;color:#9f1239;font-weight:600;line-height:1.6;\">⚠️ <span id=\"reportConfirmTxt\"></span></div>\n    </div>\n    <div class=\"modal-foot\">\n      <button class=\"btn-out\" onclick=\"closeModal('reportModal')\">Cancelar</button>\n      <button class=\"btn-main\" id=\"reportSubmitBtn\" onclick=\"submitReport()\" style=\"background:var(--red);\">Denunciar →</button>\n    </div>\n  </div>\n</div>\n\n<!-- CHANNEL MODAL -->\n<div class=\"overlay\" id=\"channelModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>Criar Canal</h3><button class=\"modal-x\" onclick=\"closeModal('channelModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"frow\"><label>Nome do canal</label><input class=\"finp\" id=\"chanName\" placeholder=\"Nome do canal\"/></div>\n      <div class=\"frow\"><label>Email do canal</label>\n        <div class=\"email-prefix-row\">\n          <input class=\"email-inp\" id=\"chanEmail\" placeholder=\"nomecanal\" oninput=\"updateChanPreview()\"/>\n          <span class=\"email-at-suffix\">@capdrawn.com</span>\n        </div>\n        <small id=\"chanEmailPreview\" style=\"color:var(--blue);font-size:.7rem;margin-top:2px;display:block;\"></small>\n        <div style=\"margin-top:6px;padding:8px 11px;background:var(--bg);border-radius:8px;font-size:.78rem;\">Email final: <strong id=\"chanEmailFinal\" style=\"color:var(--blue);\">email@capdrawn.com</strong></div>\n      </div>\n      <div class=\"frow\"><label>Senha</label><input class=\"finp\" type=\"password\" id=\"chanPass\" placeholder=\"Senha do canal\"/></div>\n    </div>\n    <div class=\"modal-foot\">\n      <button class=\"btn-out\" onclick=\"closeModal('channelModal')\">Cancelar</button>\n      <button class=\"btn-main\" onclick=\"createChannel()\">Criar →</button>\n    </div>\n  </div>\n</div>\n\n<!-- DESCRIPTION SHEET -->\n<div class=\"sheet-overlay\" id=\"descSheet\" onclick=\"if(event.target===this)closeSheet()\">\n  <div class=\"sheet\">\n    <div class=\"sheet-handle\"><div class=\"sheet-handle-bar\"></div></div>\n    <div class=\"sheet-header\"><h3>Descrição</h3><button class=\"sheet-close\" onclick=\"closeSheet()\">✕</button></div>\n    <div class=\"sheet-body\">\n      <div class=\"sheet-sec\">Sobre o canal</div>\n      <div class=\"sheet-desc-text\" id=\"sheetDesc\">—</div>\n      <div class=\"sheet-sec2\">Mais informações</div>\n      <div style=\"border-top:1px solid var(--border);padding:10px 0;font-size:.84rem;color:var(--t2);display:flex;align-items:center;gap:12px;\"><span style=\"font-size:1rem;\">📅</span><span id=\"sheetCreated\">—</span></div>\n      <div style=\"border-top:1px solid var(--border);padding:10px 0;font-size:.84rem;color:var(--t2);display:flex;align-items:center;gap:12px;\"><span style=\"font-size:1rem;\">👁</span><span id=\"sheetViews\">—</span></div>\n    </div>\n  </div>\n</div>\n\n<div class=\"toast\" id=\"toast\"></div>\n\n<!-- MAINTENANCE PAGE -->\n<div id=\"maintenancePage\">\n  <div class=\"maint-icon\">🔧</div>\n  <div class=\"maint-title\">Em Manutenção</div>\n  <div class=\"maint-sub\" id=\"maintMsg\">Estamos melhorando a plataforma para você. Voltamos em breve!</div>\n  <div class=\"maint-date\" id=\"maintDate\"></div>\n  <span class=\"maint-adm-link\" onclick=\"promptAdmLogin()\">Acesso administrativo</span>\n</div>\n\n<!-- ADM CHIP — aparece só quando manutenção está ativa -->\n<div id=\"admBar\" onclick=\"openAdmPanel()\" title=\"Manutenção ativa — clique para abrir o painel\">\n  <div class=\"adm-bar-label\">🔧 <span id=\"admMaintStatus\">Manutenção ativa</span></div>\n</div>\n\n<!-- POLICY MODAL -->\n<div class=\"overlay\" id=\"policyModal\">\n  <div class=\"modal\" style=\"max-height:88vh;\">\n    <div class=\"modal-head\">\n      <h3>📋 Políticas da Plataforma</h3>\n      <button class=\"modal-x\" onclick=\"closeModal('policyModal')\">✕</button>\n    </div>\n    <div class=\"modal-body\">\n      <div class=\"policy-section\">\n        <h4>🎯 O que é o CapDrawn?</h4>\n        <p>CapDrawn é uma rede social de entretenimento focada em memes, vídeos de produção pessoal e divulgação de projetos criativos. A plataforma simula dinâmicas de crescimento em redes sociais, proporcionando uma experiência divertida e educativa sobre produção de conteúdo digital.</p>\n      </div>\n      <div class=\"policy-section\">\n        <h4>⚠️ Audiência e Visibilidade</h4>\n        <p>A plataforma pode exibir métricas simuladas (visualizações, seguidores, popularidade) com fins de entretenimento. Ainda assim, conteúdos públicos são acessíveis a visitantes reais da plataforma. Publique com responsabilidade.</p>\n      </div>\n      <div class=\"policy-section\">\n        <h4>✅ Conteúdo Permitido</h4>\n        <ul>\n          <li>Memes originais e recriações criativas</li>\n          <li>Vídeos de produção pessoal e projetos autorais</li>\n          <li>Divulgação de projetos digitais e criativos</li>\n          <li>Conteúdo humorístico dentro dos limites desta política</li>\n        </ul>\n      </div>\n      <div class=\"policy-section\">\n        <h4>🚫 Conteúdo Proibido</h4>\n        <p>Todo conteúdo que, de qualquer forma, menospreze, ofenda ou atinja negativamente a dignidade de qualquer pessoa ou grupo de pessoas — independentemente de suas características, crenças, origem ou identidade — será bloqueado imediatamente, sem aviso prévio.</p>\n        <ul>\n          <li>Linguagem agressiva, ameaças ou intimidação</li>\n          <li>Conteúdo sexualmente explícito ou impróprio</li>\n          <li>Divulgação de dados pessoais de terceiros</li>\n          <li>Spam, golpes ou conteúdo enganoso</li>\n          <li>Nomes de usuário, comentários ou títulos ofensivos</li>\n        </ul>\n      </div>\n      <div class=\"policy-section\">\n        <h4>🔒 Moderação Automática</h4>\n        <p>A plataforma utiliza sistemas automáticos de moderação que analisam vídeos, comentários e nomes de canal antes da publicação. Tentativas de burlar o sistema usando caracteres especiais, símbolos ou substituições de letras são detectadas e bloqueadas.</p>\n      </div>\n      <div class=\"policy-section\">\n        <h4>📅 Criação da Plataforma</h4>\n        <p>Projeto CapDrawn — criado em <strong>19 de dezembro de 2017</strong>.</p>\n      </div>\n    </div>\n    <div class=\"modal-foot\">\n      <button class=\"btn-main\" onclick=\"closeModal('policyModal')\">Entendido ✓</button>\n    </div>\n  </div>\n</div>\n\n<!-- ADM PANEL MODAL -->\n<div class=\"overlay\" id=\"admPanelModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>🛡️ Painel ADM</h3><button class=\"modal-x\" onclick=\"closeModal('admPanelModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <div class=\"frow\"><label>Status da Plataforma</label>\n        <div style=\"display:flex;gap:8px;align-items:center;\">\n          <div id=\"admStatusDot\" style=\"width:10px;height:10px;border-radius:50%;background:var(--green);\"></div>\n          <span id=\"admStatusTxt\" style=\"font-size:.84rem;font-weight:700;\">Online</span>\n        </div>\n      </div>\n      <div class=\"frow\"><label>Comunicado de Manutenção</label>\n        <textarea class=\"finp\" id=\"admMaintMsgInp\" placeholder=\"Mensagem exibida durante a manutenção…\" style=\"min-height:70px;resize:none;\"></textarea>\n      </div>\n      <div class=\"frow\"><label>Previsão de Retorno (opcional)</label>\n        <input class=\"finp\" type=\"datetime-local\" id=\"admMaintDate\"/>\n      </div>\n      <div style=\"display:flex;gap:8px;margin-top:4px;\">\n        <button class=\"btn-main\" style=\"flex:1;justify-content:center;background:var(--red);\" onclick=\"toggleMaintenance()\">\n          <span id=\"admMaintBtnTxt\">🔧 Ativar Manutenção</span>\n        </button>\n        <button class=\"btn-out\" style=\"flex:1;justify-content:center;\" onclick=\"closeModal('admPanelModal')\">Fechar</button>\n      </div>\n    </div>\n  </div>\n</div>\n\n<!-- STORE MODAL -->\n<div class=\"overlay\" id=\"storeModal\">\n  <div class=\"modal\">\n    <div class=\"modal-head\"><h3>🏪 Loja de Decorações</h3><button class=\"modal-x\" onclick=\"closeModal('storeModal')\">✕</button></div>\n    <div class=\"modal-body\">\n      <p style=\"font-size:.75rem;color:var(--t3);margin-bottom:14px;\">Personalize seu nome e perfil com decorações exclusivas. Desbloqueie itens atingindo marcos na plataforma.</p>\n      <div class=\"store-grid\" id=\"storeGrid\"></div>\n    </div>\n  </div>\n</div>\n\n<script>\n// ═══════════════════════════════════════\n// APP STATE\n// ═══════════════════════════════════════\nconst APP = {\n  me: null,\n  token: null,\n  subscribers: new Set(),\n  payLinks: {tiktok:'https://lite.tiktok.com/ref/capdrawnn',yt:'https://youtube.com/@capdrawnn'},\n};\n\n\n// IN-APP BROWSER DETECTION\nfunction isInAppBrowser() {\n  var ua = navigator.userAgent || '';\n  return /Instagram|FBAN|FBAV|Rezona|MicroMessenger|Line|Twitter|TikTok|Snapchat|Pinterest|LinkedInApp|WhatsApp|Viber/.test(ua) || typeof window.ReactNativeWebView !== 'undefined';\n}\nfunction openInBrowserInstructions() {\n  var url = window.location.href;\n  var isAndroid = /Android/.test(navigator.userAgent);\n  var isIOS = /iPhone|iPad|iPod/.test(navigator.userAgent);\n  var steps = isAndroid ? '1. Toque nos tres pontos no canto superior\\\n2. Toque em Abrir no Chrome ou Abrir no navegador\\\n3. Publique normalmente!' : isIOS ? '1. Toque em Compartilhar\\\n2. Toque em Abrir no Safari\\\n3. Publique normalmente!' : 'Copie o link abaixo e abra no Chrome ou Safari.';\n  var m = document.getElementById('inAppModal');\n  if (!m) { m = document.createElement('div'); m.id = 'inAppModal'; m.style.cssText = 'display:none;position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;align-items:flex-end;justify-content:center;backdrop-filter:blur(4px);'; document.body.appendChild(m); }\n  m.innerHTML = '<div style=\"background:#fff;border-radius:20px 20px 0 0;width:100%;max-width:480px;padding:24px 20px 36px;\"><div style=\"font-size:2rem;text-align:center;margin-bottom:8px;\">\\ud83d\\udcf1</div><h3 style=\"font-size:1rem;font-weight:800;text-align:center;margin-bottom:6px;\">Abra no navegador para publicar</h3><p style=\"font-size:.82rem;color:#52527a;text-align:center;line-height:1.6;margin-bottom:14px;\">Este app nao permite acesso a galeria.<br>Siga os passos:</p><div style=\"background:#f6f6f9;border-radius:10px;padding:14px;font-size:.84rem;line-height:2;white-space:pre-line;margin-bottom:14px;\">' + steps + '</div><div style=\"display:flex;gap:8px;background:#eef3ff;border:1.5px solid #c0cffb;border-radius:10px;padding:10px 12px;margin-bottom:14px;\"><span style=\"font-size:.7rem;color:#0052e0;flex:1;word-break:break-all;\">' + url + '</span><button onclick=\"navigator.clipboard&&navigator.clipboard.writeText(\\'' + url + '\\');toast(\\'Link copiado!\\')\" style=\"flex-shrink:0;padding:5px 10px;background:#0052e0;color:#fff;border:none;border-radius:7px;font-size:.72rem;font-weight:700;cursor:pointer;\">Copiar</button></div><button onclick=\"document.getElementById(\\'inAppModal\\').style.display=\\'none\\'\" style=\"width:100%;padding:12px;background:#0b0b14;color:#fff;border:none;border-radius:12px;font-size:.88rem;font-weight:700;cursor:pointer;\">Fechar</button></div>';\n  m.style.display = 'flex';\n  m.onclick = function(e) { if(e.target===m) m.style.display='none'; };\n}\n\n// Cache de usuários (inclui bots do banco)\nconst USERS = {};\n// Comentários do CHAT DA HOME (local + bots — NÃO são comentários de vídeos)\nlet HOME_COMMENTS = [];\nlet nextLocalId = 1000;\n\nconst EMBLEMAS = [\n  {id:'e1',emoji:'💀',name:'Meme Lord',color:'#f0f0f0',req:'free'},\n  {id:'e2',emoji:'🔥',name:'Viral',color:'#fff3e0',req:'free'},\n  {id:'e3',emoji:'🏆',name:'Top',color:'#fff0e8',req:'vip'},\n  {id:'e4',emoji:'💎',name:'Diamante',color:'#f0e8ff',req:'ultra'},\n  {id:'e5',emoji:'👁',name:'Watcher',color:'#e8f0ff',req:'vip'},\n  {id:'e6',emoji:'🌟',name:'Estrela',color:'#fffff0',req:'ultra'},\n];\n\nconst BADGE_COLORS = {\n  memes:{bg:'#fff3e0',c:'#e65100'},\n  gaming:{bg:'#e8fff5',c:'#00a060'},\n  criador:{bg:'#eef3ff',c:'#0052e0'},\n  musica:{bg:'#f3e5f5',c:'#6a1b9a'},\n};\nconst BADGE_ICONS = {memes:'💀',gaming:'🎮',criador:'🎬',musica:'🎵'};\nconst AV_CLASSES = [\"av-1\",\"av-2\",\"av-3\",\"av-4\",\"av-5\",\"av-6\",\"av-7\",\"av-8\"];\nconst BN_CLASSES = [\"bn-1\",\"bn-2\",\"bn-3\",\"bn-4\",\"bn-5\",\"bn-6\",\"bn-7\",\"bn-8\"];\n\n// Pool de comentários do chat da home (bots comentam APENAS aqui)\nconst BOT_COMMENTS_HOME = [\n  \"Bem-vindos ao CapDrawn MemeShorts 💀\",\"Feed da comunidade ativo.\",\"Sistema operacional 100%.\",\"Memes chegando em breve.\",\"@arquivo.secreto online.\",\"Transmissão iniciada.\",\"Canal monitorado ativo.\",\"Uploads habilitados — publique seu conteúdo.\",\"Feed global sincronizado.\",\"Rede de distribuição pronta.\",\n];\n\nfunction rand(a){return a[Math.floor(Math.random()*a.length)];}\nfunction randInt(min,max){return Math.floor(Math.random()*(max-min+1))+min;}\n\n// ═══════════════════════════════════════\n// BOTS (carregados do banco via API)\n// ═══════════════════════════════════════\nlet botsLoaded = false;\nlet botList = []; // lista de {handle, name, avatarUrl, isVerified, isVip}\n\nasync function loadBots() {\n  if (botsLoaded) return;\n  try {\n    const res = await fetch('/api/users?bots=1');\n    if (res.ok) {\n      const data = await res.json();\n      if (data.ok && data.users) {\n        data.users.filter(u => u.isBot).forEach(u => {\n          USERS[u.handle] = { ...u, isBot: true, avClass: AV_CLASSES[Math.abs(hashStr(u.handle)) % 8], bnClass: BN_CLASSES[Math.abs(hashStr(u.handle)) % 8] };\n          botList.push(u);\n        });\n        botsLoaded = true;\n        // Popula o select de bots no upload\n        populateBotSelect();\n      }\n    }\n  } catch(e) {}\n}\n\nfunction hashStr(s) { return s.split('').reduce((a,c)=>a+c.charCodeAt(0),0); }\n\nfunction getRandomBot() {\n  if (!botList.length) return null;\n  return botList[Math.floor(Math.random() * botList.length)];\n}\n\nfunction populateBotSelect() {\n  const sel = document.getElementById('botPickerSelect');\n  if (!sel) return;\n  // Remove opções antigas (mantém \"aleatório\")\n  while (sel.options.length > 1) sel.remove(1);\n  botList.forEach(b => {\n    const opt = document.createElement('option');\n    opt.value = b.handle;\n    opt.textContent = `@${b.handle} — ${b.name}`;\n    sel.appendChild(opt);\n  });\n}\n\n// ═══════════════════════════════════════\n// FEED DE VÍDEOS (do banco de dados)\n// ═══════════════════════════════════════\nlet feedVideos = [];       // vídeos carregados da API\nlet feedPage = 1;\nlet feedLoading = false;\nlet currentFeedTab = 'all';\nlet audioUnlocked = false; // torna-se true após primeira interação real do usuário\nlet currentVidForComments = null;\nlet currentReportVidId = null;\nlet selectedDist = 'profile';\nlet publishMenuOpen = false;\nlet reportType = null;\nlet copyrightType = null;\n\nasync function loadFeedVideos(reset = false) {\n  if (feedLoading) return;\n  feedLoading = true;\n  if (reset) { feedVideos = []; feedPage = 1; }\n  try {\n    const res = await fetch(`/api/videos/feed?page=${feedPage}&limit=10&tab=${currentFeedTab}`);\n    if (res.ok) {\n      const data = await res.json();\n      if (data.ok && data.videos) {\n        data.videos.forEach(v => {\n          // Registra uploader e bot no USERS cache\n          if (v.uploader && !USERS[v.uploader.handle]) USERS[v.uploader.handle] = { ...v.uploader, isBot: v.uploader.isBot || false, videos: [], avClass: AV_CLASSES[hashStr(v.uploader.handle)%8], bnClass: BN_CLASSES[hashStr(v.uploader.handle)%8] };\n          if (v.distributor && !USERS[v.distributor.handle]) USERS[v.distributor.handle] = { ...v.distributor, isBot: true, avClass: AV_CLASSES[hashStr(v.distributor.handle)%8], bnClass: BN_CLASSES[hashStr(v.distributor.handle)%8] };\n          feedVideos.push(v);\n        });\n        feedPage++;\n      }\n    }\n  } catch(e) {}\n  feedLoading = false;\n}\n\nfunction openVideoFeed(tab) {\n  if (tab) currentFeedTab = tab;\n  const feed = document.getElementById('videoFeedPage');\n  const container = document.getElementById('videoFeedContainer');\n  feed.style.display = 'block';\n  document.body.style.overflow = 'hidden';\n  setActiveNav('bnavVideos');\n  container.innerHTML = '';\n  feedVideos = []; feedPage = 1;\n  // O clique que abriu o feed já conta como interação — desbloqueia áudio\n  audioUnlocked = true;\n  requestAnimationFrame(() => {\n    loadFeedVideos(true).then(() => {\n      renderFeedItems(container);\n      setupVidObserver(container);\n      // Dispara fakeviews em background\n      fetch('/api/videos/fakeviews', {method:'POST'}).catch(()=>{});\n    });\n  });\n}\n\nfunction renderFeedItems(container) {\n  if (!feedVideos.length) {\n    container.innerHTML = `<div style=\"position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:rgba(255,255,255,.5);font-size:.9rem;text-align:center;padding:20px;\">Nenhum vídeo ainda.<br/>Publique o primeiro!</div>`;\n    return;\n  }\n  feedVideos.forEach(v => {\n    const el = buildVideoCard(v);\n    container.appendChild(el);\n  });\n}\n\nfunction buildVideoCard(v) {\n  const item = document.createElement('div');\n  item.className = 'vid-snap-item';\n  item.dataset.vidId = v.id;\n\n  // Quem aparece como publicador: bot (se distribuído) ou uploader\n  const presenter = v.distributor || v.uploader;\n  const presenterHandle = presenter?.handle || 'usuario';\n  const presenterName   = presenter?.name   || 'Canal';\n  const presenterAv     = presenter?.avatarUrl;\n  const avInit = (presenterName||'?').charAt(0).toUpperCase();\n  const avHtml = presenterAv\n    ? `<img src=\"${presenterAv}\" style=\"width:100%;height:100%;object-fit:cover;\" onerror=\"this.style.display='none';this.parentElement.textContent='${avInit}';\"/>`\n    : avInit;\n\n  // Copyright notice (vídeo distribuído por bot)\n  let copyrightHtml = '';\n  if (v.distributor) {\n    const realOwner = v.sentBy || (!v.uploader?.isBot ? v.uploader : null);\n    if (realOwner && realOwner.handle !== v.distributor.handle) {\n      copyrightHtml = `<div class=\"vid-copyright\">📝 Enviado por: <a onclick=\"openProfileFromFeed('${realOwner.handle}')\">@${realOwner.handle}</a> · Distribuidor: <a onclick=\"openProfileFromFeed('${v.distributor.handle}')\">@${v.distributor.handle}</a></div>`;\n    } else {\n      copyrightHtml = `<div class=\"vid-copyright\">🤖 Distribuído por <a onclick=\"openProfileFromFeed('${v.distributor.handle}')\">@${v.distributor.handle}</a></div>`;\n    }\n  }\n\n  item.innerHTML = `\n    <video src=\"${v.url}\" playsinline loop preload=\"metadata\"\n      style=\"position:absolute;inset:0;width:100%;height:100%;object-fit:cover;cursor:pointer;\"\n      onclick=\"toggleVidPlay(this,'${v.id}')\">\n    </video>\n    <div class=\"vid-overlay\"></div>\n    <div class=\"vid-pause-icon\" id=\"pauseIcon${v.id}\">\n      <svg width=\"28\" height=\"28\" viewBox=\"0 0 28 28\" fill=\"white\"><rect x=\"6\" y=\"5\" width=\"5\" height=\"18\" rx=\"2\"/><rect x=\"17\" y=\"5\" width=\"5\" height=\"18\" rx=\"2\"/></svg>\n    </div>\n    <button class=\"vid-report-btn\" onclick=\"openReportModal('${v.id}')\">⚑ Denunciar</button>\n    <div class=\"vid-info\">\n      <div class=\"vid-author\" onclick=\"openProfileFromFeed('${presenterHandle}')\">\n        <div class=\"vid-av\">${avHtml}</div>\n        <div>\n          <div class=\"vid-author-name\">${presenterName}${presenter?.isVerified?'<span style=\"display:inline-flex;align-items:center;justify-content:center;width:13px;height:13px;background:#0052e0;clip-path:polygon(50% 0%,100% 50%,50% 100%,0% 50%);margin-left:3px;\"><svg width=\"7\" height=\"7\" viewBox=\"0 0 24 24\" fill=\"white\"><path d=\"M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z\"/></svg></span>':''}</div>\n          <div class=\"vid-author-handle\">@${presenterHandle}</div>\n        </div>\n      </div>\n      <div class=\"vid-caption\">${v.caption || ''}</div>\n      ${copyrightHtml}\n    </div>\n    <div class=\"vid-side-actions\">\n      <button class=\"vid-heart-btn\" id=\"likeBtn${v.id}\" onclick=\"likeVid('${v.id}',this)\">\n        <svg width=\"30\" height=\"30\" viewBox=\"0 0 30 30\" fill=\"none\" stroke=\"white\" stroke-width=\"2\"><path d=\"M15 26S4 19 4 11a6 6 0 0112 0A6 6 0 0126 11c0 8-11 15-11 15z\"/></svg>\n        <span class=\"vid-act-count\" id=\"vlikeCount${v.id}\">${formatNum(v.likes||0)}</span>\n      </button>\n      <button class=\"vid-act-btn\" onclick=\"openVidComments('${v.id}')\">\n        <svg width=\"28\" height=\"28\" viewBox=\"0 0 28 28\" fill=\"none\" stroke=\"white\" stroke-width=\"2\"><path d=\"M4 4h20v16H16l-4 4v-4H4V4z\" stroke-linejoin=\"round\"/></svg>\n        <span class=\"vid-act-count\" id=\"vcmtCount${v.id}\">${v.comments||0}</span>\n      </button>\n      <button class=\"vid-act-btn\" onclick=\"shareVid('${v.id}')\">\n        <svg width=\"26\" height=\"26\" viewBox=\"0 0 26 26\" fill=\"none\" stroke=\"white\" stroke-width=\"2\"><circle cx=\"20\" cy=\"5\" r=\"3\"/><circle cx=\"6\" cy=\"13\" r=\"3\"/><circle cx=\"20\" cy=\"21\" r=\"3\"/><path d=\"M8.5 11.5l9-5M8.5 14.5l9 5\"/></svg>\n        <span class=\"vid-act-count\">⎋</span>\n      </button>\n    </div>`;\n  return item;\n}\n\nlet _feedObserver = null;\n\nfunction setupVidObserver(container) {\n  if (_feedObserver) { _feedObserver.disconnect(); _feedObserver = null; }\n  const observer = new IntersectionObserver(entries => {\n    entries.forEach(e => {\n      const vid = e.target.querySelector('video');\n      if (vid) {\n        if (e.isIntersecting) {\n          container.querySelectorAll('video').forEach(v => { if (v !== vid) { v.pause(); } });\n          vid.muted = !audioUnlocked;\n          vid.play().catch(() => { vid.muted = true; vid.play().catch(()=>{}); });\n          const vidId = e.target.dataset.vidId;\n          if (vidId) fetch(`/api/videos/${vidId}/interact`, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action:'view'})}).catch(()=>{});\n        } else {\n          vid.pause();\n        }\n      }\n      if (e.isIntersecting) {\n        const all = container.querySelectorAll('.vid-snap-item');\n        const idx = Array.from(all).indexOf(e.target);\n        if (all.length - idx <= 2) loadMoreFeedItems(container);\n      }\n    });\n  }, {threshold: 0.5, root: container});\n  container.querySelectorAll('.vid-snap-item').forEach(el => observer.observe(el));\n  _feedObserver = observer;\n}\n\nlet isAddingMore = false;\nasync function loadMoreFeedItems(container) {\n  if (isAddingMore || feedLoading) return;\n  isAddingMore = true;\n  const prevLen = feedVideos.length;\n  await loadFeedVideos();\n  const newVideos = feedVideos.slice(prevLen);\n  newVideos.forEach(v => {\n    const el = buildVideoCard(v);\n    container.appendChild(el);\n    if (_feedObserver) _feedObserver.observe(el);\n  });\n  isAddingMore = false;\n}\n\nfunction toggleVidPlay(vidEl, vidId) {\n  const icon = document.getElementById('pauseIcon' + vidId);\n  audioUnlocked = true;\n  if (vidEl.muted) vidEl.muted = false;\n  if (vidEl.paused) {\n    vidEl.play();\n    if (icon) icon.classList.remove('show');\n  } else {\n    vidEl.pause();\n    if (icon) { icon.classList.add('show'); setTimeout(() => icon.classList.remove('show'), 1200); }\n  }\n}\n\nfunction startShortsFromSplash() {\n  // Essa função é chamada por clique humano — áudio liberado\n  const splash = document.getElementById('shortsSplash');\n  splash.classList.remove('show');\n  audioUnlocked = true;\n  const el = document.getElementById('ftShorts');\n  openVideoFeed('shorts');\n  if (el) {\n    document.querySelectorAll('.feed-tab').forEach(t => t.classList.remove('active'));\n    el.classList.add('active');\n  }\n}\n\nfunction closeVideoFeed() {\n  document.querySelectorAll('#videoFeedContainer video').forEach(v => v.pause());\n  document.getElementById('videoFeedPage').style.display = 'none';\n  document.body.style.overflow = '';\n  history.replaceState(null, '', location.pathname); // limpa #shorts da URL\n  setActiveNav('bnavHome');\n  audioUnlocked = false;\n}\n\nfunction switchFeedTab(tab, el) {\n  currentFeedTab = tab;\n  document.querySelectorAll('.feed-tab').forEach(t => t.classList.remove('active'));\n  el.classList.add('active');\n  // Atualiza URL para compartilhar\n  history.replaceState(null, '', tab === 'shorts' ? '#shorts' : '#feed');\n  // Recarrega o feed com a nova aba\n  const container = document.getElementById('videoFeedContainer');\n  container.innerHTML = '';\n  feedVideos = []; feedPage = 1;\n  requestAnimationFrame(() => {\n    loadFeedVideos(true).then(() => { renderFeedItems(container); setupVidObserver(container); });\n  });\n}\n\nfunction openProfileFromFeed(handle) { closeVideoFeed(); setTimeout(() => openProfile(handle), 100); }\n\nasync function likeVid(id, btn) {\n  if (!APP.me) { openLogin(); return; }\n  try {\n    const res = await fetch(`/api/videos/${id}/interact`, {\n      method: 'POST',\n      headers: {'Content-Type':'application/json', 'Authorization': 'Bearer '+APP.token},\n      body: JSON.stringify({action:'like'})\n    });\n    const data = await res.json();\n    if (data.ok) {\n      if (data.liked) { btn.classList.add('liked'); btn.style.transform='scale(1.3)'; setTimeout(()=>btn.style.transform='',200); }\n      else { btn.classList.remove('liked'); }\n      const cnt = document.getElementById('vlikeCount' + id);\n      if (cnt) cnt.textContent = formatNum(data.totalLikes || 0);\n    }\n  } catch(e) { toast('❌ Erro ao dar like'); }\n}\n\nfunction shareVid(id) {\n  if (navigator.share) navigator.share({title:'CapDrawn',url:window.location.href}).catch(()=>{});\n  else { navigator.clipboard?.writeText(window.location.href); toast('🔗 Link copiado!'); }\n}\n\n// ═══════════════════════════════════════\n// COMENTÁRIOS DE VÍDEO (do banco de dados)\n// ═══════════════════════════════════════\nasync function openVidComments(id) {\n  currentVidForComments = id;\n  const v = feedVideos.find(x => x.id === id);\n  openModal('videoCommentsModal');\n  document.getElementById('vcModalTitle').textContent = 'Comentários';\n  document.getElementById('videoCommentsList').innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--t3);font-size:.82rem;\">Carregando…</div>';\n  document.getElementById('vcSaveStatus').style.display = 'none';\n\n  // Avatar do usuário logado\n  const av = document.getElementById('vcCompAv');\n  if (APP.me) {\n    av.style.background = APP.me.color || 'var(--blue)';\n    av.textContent = APP.me.name.charAt(0).toUpperCase();\n    if (APP.me.avatar) av.innerHTML = `<img src=\"${APP.me.avatar}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\"/>`;\n  }\n\n  // Carrega comentários reais do banco\n  try {\n    const res = await fetch(`/api/comments?videoId=${id}`);\n    const data = await res.json();\n    if (data.ok) {\n      document.getElementById('vcModalTitle').textContent = `Comentários (${data.comments.length})`;\n      renderVidComments(data.comments);\n    } else {\n      document.getElementById('videoCommentsList').innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--red);font-size:.82rem;\">Erro ao carregar comentários.</div>';\n    }\n  } catch(e) {\n    document.getElementById('videoCommentsList').innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--red);font-size:.82rem;\">Sem conexão. Verifique o servidor.</div>';\n  }\n}\n\nfunction renderVidComments(comments) {\n  const list = document.getElementById('videoCommentsList');\n  if (!comments.length) {\n    list.innerHTML = `<div style=\"text-align:center;padding:24px 0;color:var(--t3);font-size:.84rem;\">Seja o primeiro a comentar!</div>`;\n    return;\n  }\n  list.innerHTML = comments.map(c => {\n    const u = c.user;\n    const avHtml = u.avatarUrl\n      ? `<img src=\"${u.avatarUrl}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\"/>`\n      : (u.name||u.handle).charAt(0).toUpperCase();\n    const verBadge = u.isVerified\n      ? `<span style=\"display:inline-flex;align-items:center;justify-content:center;width:12px;height:12px;background:var(--blue);clip-path:polygon(50% 0%,100% 50%,50% 100%,0% 50%);margin-left:2px;\"><svg width=\"7\" height=\"7\" viewBox=\"0 0 24 24\" fill=\"white\"><path d=\"M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z\"/></svg></span>` : '';\n    const vipBadge = u.isVip\n      ? `<span style=\"font-size:.55rem;padding:1px 4px;background:var(--vip-lt);border:1px solid var(--vip-bd);border-radius:3px;color:var(--vip);font-weight:700;\">⭐</span>` : '';\n    const timeAgo = formatTimeAgo(c.createdAt);\n    const isPinnedCmt = pinnedVidComments[currentVidForComments] === c.id;\n    const isOwner = APP.me && feedVideos.find(v=>v.id===currentVidForComments)?.uploader?.handle === APP.me.handle;\n    return `<div class=\"vcmt\" ${isPinnedCmt?'style=\"border-color:var(--gold);background:#fffbeb;\"':''}>\n      ${isPinnedCmt?'<div class=\"vid-pin-badge\">📌 Fixado</div>':''}\n      <div class=\"vcmt-av\" style=\"background:#0052e0;\" onclick=\"openProfileFromComments('${u.handle}')\">${avHtml}</div>\n      <div style=\"flex:1;min-width:0;\">\n        <div style=\"display:flex;align-items:center;gap:4px;flex-wrap:wrap;\">\n          <span class=\"vcmt-name\" onclick=\"openProfileFromComments('${u.handle}')\">${u.name}</span>${verBadge}${vipBadge}\n          <span class=\"vcmt-time\">${timeAgo}</span>\n          ${isOwner?`<span style=\"font-size:.6rem;color:var(--gold);cursor:pointer;margin-left:auto;\" onclick=\"pinVidComment('${currentVidForComments}','${c.id}')\">${isPinnedCmt?'📌 Desafixar':'📌 Fixar'}</span>`:''}\n        </div>\n        <div class=\"vcmt-text\">${parseMentions(c.text)}</div>\n      </div>\n    </div>`;\n  }).join('');\n}\n\nfunction openProfileFromComments(handle) { closeModal('videoCommentsModal'); setTimeout(() => openProfile(handle), 80); }\n\nasync function sendVidComment() {\n  if (!APP.me) { closeModal('videoCommentsModal'); openLogin(); return; }\n  const text = document.getElementById('vcInput').value.trim();\n  if (!text) return;\n  if (!moderateText(text, 'comment')) return;\n  const apiOk = await moderateViaAPI(text);\n  if (!apiOk) { toast('🚫 Comentário bloqueado pela análise de conteúdo.'); return; }\n\n  const statusEl = document.getElementById('vcSaveStatus');\n  statusEl.className = 'vcmt-status';\n  statusEl.textContent = '⏳ Salvando comentário…';\n  statusEl.style.display = 'block';\n\n  try {\n    const res = await fetch('/api/comments', {\n      method: 'POST',\n      headers: {'Content-Type':'application/json', 'Authorization':'Bearer '+APP.token},\n      body: JSON.stringify({ text, videoId: currentVidForComments })\n    });\n    const data = await res.json();\n\n    if (data.ok && data.saved) {\n      statusEl.className = 'vcmt-status ok';\n      statusEl.textContent = '✅ Comentário salvo com sucesso!';\n      document.getElementById('vcInput').value = '';\n      hideVcMentDrop();\n      // Recarrega a lista do banco para confirmar\n      const res2 = await fetch(`/api/comments?videoId=${currentVidForComments}`);\n      const data2 = await res2.json();\n      if (data2.ok) {\n        document.getElementById('vcModalTitle').textContent = `Comentários (${data2.comments.length})`;\n        renderVidComments(data2.comments);\n        // Atualiza contador no feed\n        const cnt = document.getElementById('vcmtCount' + currentVidForComments);\n        if (cnt) cnt.textContent = data2.comments.length;\n      }\n      setTimeout(() => { statusEl.style.display = 'none'; }, 3000);\n    } else {\n      statusEl.className = 'vcmt-status err';\n      statusEl.textContent = '❌ ' + (data.error || 'Erro ao salvar. Tente novamente.');\n    }\n  } catch(e) {\n    statusEl.className = 'vcmt-status err';\n    statusEl.textContent = '❌ Sem conexão com o servidor.';\n  }\n}\n\nfunction onVcMentInput(el) {\n  const v = el.value, la = v.lastIndexOf('@');\n  if (la === -1) { hideVcMentDrop(); return; }\n  const q = v.slice(la+1).toLowerCase();\n  if (!q) { hideVcMentDrop(); return; }\n  const matches = Object.values(USERS).filter(u => u.handle?.startsWith(q) || u.name?.toLowerCase().startsWith(q)).slice(0,5);\n  if (!matches.length) { hideVcMentDrop(); return; }\n  const drop = document.getElementById('vcMentDrop');\n  drop.innerHTML = matches.map(u => `<div class=\"ment-item\" onclick=\"complVcMent('${u.handle}')\">\n    <div class=\"cav\" style=\"width:28px;height:28px;background:#0052e0;\">${(u.name||u.handle).charAt(0).toUpperCase()}</div>\n    <div><strong style=\"font-size:.8rem;\">${u.name}</strong><div style=\"font-size:.68rem;color:var(--t3);\">@${u.handle}</div></div>\n  </div>`).join('');\n  drop.classList.add('show');\n}\nfunction complVcMent(h) { const inp=document.getElementById('vcInput'),v=inp.value,la=v.lastIndexOf('@');inp.value=v.slice(0,la+1)+h+' ';hideVcMentDrop();inp.focus(); }\nfunction hideVcMentDrop() { document.getElementById('vcMentDrop').classList.remove('show'); }\n\n// ═══════════════════════════════════════\n// MENCIONES\n// ═══════════════════════════════════════\nfunction parseMentions(text) {\n  return (text||'').replace(/@([a-zA-Z0-9_.]+)/g, (match, handle) => {\n    const u = USERS[handle] || USERS[handle.toLowerCase()];\n    if (u) return `<span class=\"mention\" onclick=\"openProfileFromComments('${u.handle}')\">${match}</span>`;\n    return `<span class=\"mention\" onclick=\"openProfile(\'${handle}\')\">${match}</span>`;\n  });\n}\n\n// ═══════════════════════════════════════\n// CHAT DA HOME (comentários locais + bots)\n// BOTS COMENTAM APENAS AQUI, NÃO EM VÍDEOS\n// ═══════════════════════════════════════\nfunction renderHomeComments() {\n  const list = document.getElementById('clist');\n  if (!HOME_COMMENTS.length) {\n    list.innerHTML = `<div style=\"text-align:center;padding:28px 0;color:var(--t3);font-size:.84rem;\">Seja o primeiro a comentar no chat!</div>`;\n    return;\n  }\n  const sorted = [...HOME_COMMENTS].sort((a,b) => (b.pinned?1:0)-(a.pinned?1:0));\n  list.innerHTML = sorted.map(c => {\n    const u = USERS[c.handle];\n    const isMe = APP.me && APP.me.handle === c.handle;\n    const avClass = u?.avClass || '';\n    const avStyle = u?.isBot ? '' : `background:${u?.color||APP.me?.color||'#888'}`;\n    const avContent = u?.avatarUrl\n      ? `<img src=\"${u.avatarUrl}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\"/>`\n      : (u?.name || c.handle).charAt(0).toUpperCase();\n    const verBadge = (u?.isVerified||u?.official) ? `<span class=\"ver-badge\"><svg viewBox=\"0 0 24 24\" width=\"8\" height=\"8\" fill=\"white\"><path d=\"M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z\"/></svg></span>` : '';\n    const vipBadge = u?.isVip ? `<span class=\"vip-seal-badge\">⭐ VIP</span>` : '';\n    const parsedText = parseMentions(c.text||'');\n    const liked = APP.me && c.likedBy?.includes(APP.me.handle);\n    return `<div class=\"comment${c.pinned?' pinned':''}\">\n      ${c.pinned?'<div class=\"pin-badge\">📌 Fixado</div>':''}\n      <div class=\"cm-top\">\n        <div class=\"cm-av ${avClass}\" style=\"${avStyle}\" onclick=\"openProfile('${c.handle}')\">${avContent}</div>\n        <div style=\"flex:1;min-width:0;\">\n          <div style=\"display:flex;align-items:center;gap:5px;flex-wrap:wrap;\">\n            <span class=\"cm-name\" onclick=\"openProfile('${c.handle}')\">${u?.name||c.handle}</span>${verBadge}${vipBadge}\n            <span class=\"cm-time\">${c.time||'agora'}</span>\n          </div>\n          <div class=\"cm-handle\">@${c.handle}</div>\n        </div>\n      </div>\n      <div class=\"cm-text\">${parsedText}</div>\n      <div class=\"cm-actions\">\n        <div class=\"cm-like${liked?' liked':''}\" onclick=\"likeHomeComment(${c.id},this)\">❤ ${c.likes||0}</div>\n        <div class=\"cm-reply\" onclick=\"replyTo('${c.handle}')\">Responder</div>\n        ${isMe?`<div class=\"cm-del\" onclick=\"delHomeComment(${c.id})\">✕ Excluir</div>`:''}\n      </div>\n    </div>`;\n  }).join('');\n}\n\nfunction sendCommunityComment() {\n  if (!APP.me) { openLogin(); return; }\n  const inp = document.getElementById('compInp');\n  const text = inp.value.trim();\n  if (!text) return;\n  if (!moderateText(text, 'comment')) return;\n  HOME_COMMENTS.unshift({id:nextLocalId++, handle:APP.me.handle, text, time:'agora', likes:0, likedBy:[], pinned:false});\n  inp.value = '';\n  hideMentDrop();\n  renderHomeComments();\n  saveHomeCommentsLocal();\n  // Bots respondem no chat da home (NÃO em comentários de vídeos)\n  if (Math.random() < 0.5 && botList.length) {\n    setTimeout(() => {\n      const rb = getRandomBot();\n      if (rb) {\n        HOME_COMMENTS.unshift({id:nextLocalId++, handle:rb.handle, text:`@${APP.me.handle} ${rand(BOT_COMMENTS_HOME)}`, time:'agora', likes:randInt(0,20), likedBy:[], pinned:false, isBot:true});\n        renderHomeComments();\n        saveHomeCommentsLocal();\n      }\n    }, 2000 + Math.random()*3000);\n  }\n}\n\nfunction likeHomeComment(id, btn) {\n  if (!APP.me) { openLogin(); return; }\n  const c = HOME_COMMENTS.find(x => x.id === id);\n  if (!c) return;\n  if (!c.likedBy) c.likedBy = [];\n  const h = APP.me.handle;\n  if (c.likedBy.includes(h)) { c.likedBy = c.likedBy.filter(x=>x!==h); c.likes = Math.max(0,(c.likes||0)-1); }\n  else { c.likedBy.push(h); c.likes = (c.likes||0)+1; }\n  renderHomeComments();\n}\n\nfunction delHomeComment(id) { HOME_COMMENTS = HOME_COMMENTS.filter(x=>x.id!==id); renderHomeComments(); saveHomeCommentsLocal(); }\nfunction replyTo(h) { const inp=document.getElementById('compInp'); inp.value=`@${h} `; inp.focus(); document.getElementById('compose').scrollIntoView({behavior:'smooth'}); }\nfunction onCompInput(el) {\n  const v=el.value, la=v.lastIndexOf('@');\n  if(la===-1){hideMentDrop();return;}\n  const q=v.slice(la+1).toLowerCase();\n  if(!q){hideMentDrop();return;}\n  const matches=Object.values(USERS).filter(u=>u.handle?.startsWith(q)||u.name?.toLowerCase().startsWith(q)).slice(0,5);\n  if(!matches.length){hideMentDrop();return;}\n  const drop=document.getElementById('mentDrop');\n  drop.innerHTML=matches.map(u=>`<div class=\"ment-item\" onclick=\"complMent('${u.handle}')\">\n    <div class=\"cav ${u.avClass||''}\" style=\"width:28px;height:28px;${u.isBot?'':('background:'+(u.color||'#888'))}\">${(u.name||u.handle).charAt(0).toUpperCase()}</div>\n    <div><strong style=\"font-size:.8rem;\">${u.name}</strong><div style=\"font-size:.68rem;color:var(--t3);\">@${u.handle}</div></div>\n  </div>`).join('');\n  drop.classList.add('show');\n}\nfunction onCompKey(e){if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendCommunityComment();}}\nfunction complMent(h){const inp=document.getElementById('compInp'),v=inp.value,la=v.lastIndexOf('@');inp.value=v.slice(0,la+1)+h+' ';hideMentDrop();inp.focus();}\nfunction hideMentDrop(){document.getElementById('mentDrop').classList.remove('show');}\nfunction insertMent(){const inp=document.getElementById('compInp');inp.value+='@';inp.focus();}\n\n// ═══════════════════════════════════════\n// PROFILE PAGE (carrega do banco)\n// ═══════════════════════════════════════\nlet viewingHandle = null;\n\nasync function openProfile(handle) {\n  if (!handle) return;\n  viewingHandle = handle;\n\n  // Tenta banco primeiro; fallback para cache local\n  try {\n    const res = await fetch(`/api/users/${handle}`);\n    if (res.ok) {\n      const data = await res.json();\n      if (data.ok) {\n        const u = data.user;\n        u.avClass = AV_CLASSES[hashStr(handle)%8];\n        u.bnClass  = BN_CLASSES[hashStr(handle)%8];\n        u.videos   = data.videos || [];\n        USERS[handle] = { ...(USERS[handle]||{}), ...u };\n        renderProfile(USERS[handle], data.videos || []);\n        return;\n      }\n    }\n  } catch(e) {}\n\n  // Fallback para cache local\n  const u = USERS[handle];\n  if (!u) { toast('Usuário não encontrado.'); return; }\n  renderProfile(u, u.videos || []);\n}\n\nfunction renderProfile(u, videos) {\n  const handle = u.handle;\n  const isMe = APP.me && APP.me.handle === handle;\n\n  document.getElementById('profBackLbl').textContent = u.name;\n\n  // Cover\n  const cov = document.getElementById('profCover');\n  if (u.isBot) {\n    document.getElementById('profCoverInner').className = 'prof-cover-inner '+(u.bnClass||'bn-1');\n    cov.style.background = '';\n  } else {\n    cov.style.background = `linear-gradient(160deg,${u.color||'#0052e0'}44 0%,${u.color||'#0052e0'}18 60%,var(--bg2) 100%)`;\n    document.getElementById('profCoverInner').className = 'prof-cover-inner';\n    document.getElementById('profCoverInner').style.background = `linear-gradient(160deg,${u.color||'#0052e0'}44,transparent)`;\n  }\n\n  // Avatar\n  const big = document.getElementById('profAvBig');\n  if (u.isBot) {\n    big.className = 'prof-av-big '+(u.avClass||'av-1');\n    big.innerHTML = u.avatarUrl\n      ? `<img src=\"${u.avatarUrl}\" onerror=\"this.style.display='none';this.parentElement.textContent='${u.name.charAt(0).toUpperCase()}'\"/>`\n      : `<span style=\"font-size:2rem;font-weight:800;color:#fff;\">${u.name.charAt(0).toUpperCase()}</span>`;\n  } else {\n    big.className = 'prof-av-big';\n    big.style.background = u.color || '#0052e0';\n    big.innerHTML = u.avatarUrl\n      ? `<img src=\"${u.avatarUrl}\" onerror=\"this.style.display='none';\"/>`\n      : `<span style=\"font-size:2rem;font-weight:800;color:#fff;\">${u.name.charAt(0).toUpperCase()}</span>`;\n  }\n\n  // Actions\n  const actions = document.getElementById('profAvActions');\n  if (isMe) {\n    actions.innerHTML = `<button class=\"prof-edit-btn\" onclick=\"closeProfile();openProfileModal();\">Editar canal</button>`;\n  } else {\n    const subd = APP.subscribers.has(handle);\n    actions.innerHTML = `\n      <button class=\"prof-follow-btn${subd?' following':''}\" id=\"profFollowBtn\" onclick=\"toggleSub()\">\n        ${subd?'Seguindo':'Seguir'}\n      </button>\n      <button class=\"prof-share-btn\" onclick=\"toast('🔗 Link copiado!')\">⎋</button>`;\n  }\n\n  // Name + seals\n  const profNameEl = document.getElementById('profName');\n  if (APP.me && u.handle === APP.me.handle && activeDecoration) {\n    profNameEl.innerHTML = getDecoratedName(u.name);\n  } else {\n    profNameEl.textContent = u.name;\n  }\n  const vs = document.getElementById('profVipSeal');\n  vs.style.display = u.isVip ? 'inline-flex' : 'none';\n  if (u.isVip) vs.innerHTML = '<span class=\"vip-seal\">⭐ VIP</span>';\n  document.getElementById('profVerCheck').style.display = (u.isVerified) ? 'inline-flex' : 'none';\n  document.getElementById('profHandle').textContent = '@'+handle;\n  document.getElementById('profMemeTag').style.display = u.isBot ? 'inline-flex' : 'none';\n\n  // Stats (do banco — reais)\n  document.getElementById('profFollowers').textContent = formatNum(u.followers||0);\n  document.getElementById('profVideos').textContent = formatNum(videos.length||0);\n  document.getElementById('profViews').textContent = formatNum(u.totalViews||0);\n\n  // Area badge\n  const badges = document.getElementById('profBadges');\n  if (u.area) badges.innerHTML = `<span class=\"badge-pill\" style=\"background:${(BADGE_COLORS[u.area]||{bg:'#eee'}).bg};color:${(BADGE_COLORS[u.area]||{c:'#666'}).c};\">${BADGE_ICONS[u.area]||''} ${u.area}</span>`;\n  else badges.innerHTML = '';\n\n  // Desc\n  const snippet = document.getElementById('profDescSnippet');\n  if (u.bio && u.bio.trim()) {\n    const short = u.bio.length>90 ? u.bio.slice(0,90)+'…' : u.bio.split('\\\n')[0];\n    snippet.innerHTML = `<span>${short}</span> <span class=\"read-more\" onclick=\"switchPTab('desc',document.querySelectorAll('.ptab')[2])\">Ler mais</span>`;\n    if (u.isBot) snippet.innerHTML += ` <button style=\"background:none;border:none;font-size:.78rem;font-weight:700;color:var(--t);cursor:pointer;padding:0;\" onclick=\"openBotSheet('${handle}')\">...mais</button>`;\n  } else snippet.innerHTML = `<span class=\"saiba-mais\" onclick=\"switchPTab('desc',document.querySelectorAll('.ptab')[2])\">Saiba mais</span>`;\n  document.getElementById('profDescFull').textContent = u.bio || '';\n  document.getElementById('profDescSection').style.display = u.bio ? 'block' : 'none';\n  document.getElementById('profDescMeta').innerHTML = `\n    <div class=\"desc-info-row\"><span class=\"desc-info-icon\">📅</span><span>${(u.handle?.toLowerCase()===ADM_HANDLE.toLowerCase()?'19 de dezembro de 2017':u.createdAt ? new Date(u.createdAt).toLocaleDateString('pt-BR',{year:'numeric',month:'long'}) : '—')}</span></div>\n    ${u.totalViews?`<div class=\"desc-info-row\"><span class=\"desc-info-icon\">👁</span><span>${formatNum(u.totalViews)} visualizações</span></div>`:''}\n    ${u.isBot?`<div class=\"desc-info-row\"><span class=\"desc-info-icon\">🤖</span><span>Canal da Rede Memes</span></div>`:''}\n    ${u.channelEmail?`<div class=\"desc-info-row\"><span class=\"desc-info-icon\">📧</span><span>${u.channelEmail}</span></div>`:''}\n  `;\n\n  // Videos grid\n  switchPTab('videos', document.querySelectorAll('.ptab')[0]);\n  renderProfVideos(u, videos, isMe);\n  renderProfEmblems(u);\n\n  document.getElementById('profilePage').style.display = 'block';\n  document.getElementById('profilePage').scrollTop = 0;\n  document.body.style.overflow = 'hidden';\n}\n\nfunction renderProfVideos(u, videos, isMe) {\n  const grid = document.getElementById('profVideoGrid');\n  const noVids = document.getElementById('profNoVideos');\n\n  if (!videos || !videos.length) {\n    noVids.style.display = 'block';\n    noVids.textContent = isMe ? 'Publique seu primeiro vídeo!' : 'Nenhum vídeo ainda.';\n    grid.innerHTML = '';\n    return;\n  }\n\n  noVids.style.display = 'none';\n  grid.innerHTML = videos.map(v => {\n    // Para vídeos enviados via bot: mostra tag do bot\n    const copyTag = v.viaBot && v.botHandle\n      ? `<div class=\"thumb-copy\" style=\"position:absolute;bottom:24px;left:4px;background:rgba(0,0,0,.7);color:#fff;font-size:.58rem;padding:2px 5px;border-radius:4px;\">🤖 @${v.botHandle}</div>` : '';\n    // Usuário pode apagar seus próprios vídeos (diretos ou enviados via bot)\n    const canDelete = isMe;\n    return `<div class=\"prof-vid-thumb\" onclick=\"playProfVid('${v.id}','${v.url}')\">\n      ${v.url\n        ? `<video src=\"${v.url}\" muted preload=\"metadata\" style=\"width:100%;height:100%;object-fit:cover;\" onloadedmetadata=\"this.currentTime=0.5\" onerror=\"this.style.display='none'\"></video>`\n        : `<div style=\"width:100%;height:100%;background:#222;display:flex;align-items:center;justify-content:center;font-size:2rem;\">🎥</div>`}\n      <div class=\"thumb-overlay\"><span class=\"thumb-play\">▶</span></div>\n      <div class=\"thumb-views\">👁 ${formatNum(v.views||0)}</div>\n      ${copyTag}\n      ${canDelete?`<button onclick=\"event.stopPropagation();confirmDeleteVideo('${v.id}')\" style=\"position:absolute;top:4px;right:4px;background:rgba(240,48,80,.8);border:none;border-radius:4px;color:#fff;font-size:.6rem;font-weight:700;padding:2px 6px;cursor:pointer;\">✕</button>`:''}\n    </div>`;\n  }).join('');\n}\n\nasync function playProfVid(id, url) {\n  let v = feedVideos.find(x => x.id === id);\n  if (!v) {\n    v = { id, url, caption: '', likes: 0, comments: 0, views: 0, uploader: null, distributor: null };\n    feedVideos.unshift(v);\n  }\n  document.getElementById('profilePage').style.display = 'none';\n  document.body.style.overflow = 'hidden';\n  const wasOpen = document.getElementById('videoFeedPage').style.display === 'block';\n  if (!wasOpen) openVideoFeed();\n  const tryScroll = (attempts) => {\n    const el = document.querySelector('[data-vid-id=\"' + id + '\"]');\n    if (el) { el.scrollIntoView({ behavior: 'instant', block: 'start' }); }\n    else if (attempts > 0) { setTimeout(() => tryScroll(attempts - 1), 100); }\n  };\n  setTimeout(() => tryScroll(10), 150);\n}\n\nasync function confirmDeleteVideo(id) {\n  if (!APP.me) return;\n  const go = confirm('Apagar este vídeo?\\\n\\\nO vídeo será removido em 5 segundos após confirmar. Baixe-o antes se quiser.');\n  if (!go) return;\n  toast('⚠️ Vídeo será apagado em 5s…');\n  setTimeout(async () => {\n    try {\n      const res = await fetch(`/api/videos/${id}`, {method:'DELETE', headers:{'Authorization':'Bearer '+APP.token}});\n      const data = await res.json();\n      if (data.ok) {\n        toast('🗑 Vídeo apagado!');\n        // Recarrega perfil\n        openProfile(APP.me.handle);\n      } else toast('❌ '+data.error);\n    } catch(e) { toast('❌ Erro ao apagar'); }\n  }, 5000);\n}\n\nfunction renderProfEmblems(u) {\n  const grid = document.getElementById('profEmbGrid');\n  grid.innerHTML = EMBLEMAS.map(e => {\n    const can = e.req==='free'||(e.req==='vip'&&u.isVip)||(e.req==='ultra'&&u.vipTier==='ultra');\n    return `<div class=\"emb${can?' owned':' locked'}\" style=\"background:${e.color};\" title=\"${e.name}${can?'':' (requer '+e.req+')'}\">${e.emoji}</div>`;\n  }).join('');\n}\n\nfunction openBotSheet(handle) {\n  const u = USERS[handle];\n  if (!u) return;\n  document.getElementById('sheetDesc').textContent = u.bio||'—';\n  document.getElementById('sheetCreated').textContent = u.createdAt ? new Date(u.createdAt).toLocaleDateString('pt-BR') : '—';\n  document.getElementById('sheetViews').textContent = u.totalViews ? formatNum(u.totalViews)+' visualizações' : '—';\n  document.getElementById('descSheet').classList.add('open');\n}\nfunction closeSheet(){document.getElementById('descSheet').classList.remove('open');}\nfunction closeProfile(){document.getElementById('profilePage').style.display='none';document.body.style.overflow='';viewingHandle=null;}\n\nfunction toggleSub() {\n  if (!viewingHandle) return;\n  if (!APP.me) { openLogin(); return; }\n  const u = USERS[viewingHandle];\n  const btn = document.getElementById('profFollowBtn');\n  if (APP.subscribers.has(viewingHandle)) {\n    APP.subscribers.delete(viewingHandle);\n    if (u) u.followers = Math.max(0,(u.followers||0)-1);\n    if (btn) { btn.textContent='Seguir'; btn.className='prof-follow-btn'; }\n  } else {\n    APP.subscribers.add(viewingHandle);\n    if (u) u.followers = (u.followers||0)+1;\n    if (btn) { btn.textContent='Seguindo'; btn.className='prof-follow-btn following'; }\n    toast(`✅ Seguindo @${viewingHandle}!`);\n  }\n  if (u) document.getElementById('profFollowers').textContent = formatNum(u.followers||0);\n}\n\nfunction switchPTab(tab, el) {\n  document.querySelectorAll('.ptab').forEach(t => t.classList.remove('active'));\n  if (el) el.classList.add('active');\n  document.getElementById('ptVideos').style.display = tab==='videos'?'block':'none';\n  document.getElementById('ptEmblems').style.display = tab==='emblems'?'block':'none';\n  document.getElementById('ptDist').style.display = tab==='dist'?'block':'none';\n  document.getElementById('ptDesc').style.display = tab==='desc'?'block':'none';\n  if (tab==='dist') renderProfDist();\n}\n\nfunction renderProfDist() {\n  if (!viewingHandle) return;\n  const u = USERS[viewingHandle];\n  const myVids = feedVideos.filter(v => v.distributor && v.uploader?.handle === viewingHandle);\n  const grid = document.getElementById('profDistGrid');\n  const noDiv = document.getElementById('profNoDist');\n  if (!myVids.length) { if(grid)grid.innerHTML=''; if(noDiv)noDiv.style.display='block'; return; }\n  if(noDiv)noDiv.style.display='none';\n  if(!grid) return;\n  grid.innerHTML = myVids.map(v => `<div class=\"prof-vid-thumb\" style=\"position:relative;\" onclick=\"playProfVid('${v.id}','${v.url}')\">\n    <video src=\"${v.url}\" muted preload=\"metadata\" style=\"width:100%;height:100%;object-fit:cover;\" onloadedmetadata=\"this.currentTime=0.5\"></video>\n    <div class=\"thumb-overlay\"><span class=\"thumb-play\">▶</span></div>\n    <div class=\"privacy-badge\">🤖 ${v.distributor?.handle||'bot'}</div>\n    <button onclick=\"event.stopPropagation();requestDistRemoval('${v.id}')\" style=\"position:absolute;bottom:4px;right:4px;background:rgba(240,48,80,.85);border:none;border-radius:4px;color:#fff;font-size:.55rem;font-weight:700;padding:2px 5px;cursor:pointer;\">Remover</button>\n  </div>`).join('');\n}\n\nasync function requestDistRemoval(id) {\n  if (!confirm('Solicitar remoção deste vídeo da distribuição?')) return;\n  try {\n    await fetch('/api/videos/'+id, {method:'DELETE', headers:{'Authorization':'Bearer '+APP.token}});\n    feedVideos = feedVideos.filter(v=>v.id!==id);\n    toast('✓ Remoção solicitada!');\n    renderProfDist();\n  } catch(e) { toast('❌ Erro ao solicitar remoção.'); }\n}\n\n// ═══════════════════════════════════════\n// RANK\n// ═══════════════════════════════════════\nasync function loadRank() {\n  try {\n    const res = await fetch('/api/rank');\n    if (!res.ok) return;\n    const data = await res.json();\n    if (!data.ok || !data.rank?.length) {\n      document.getElementById('rankList').innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--t3);font-size:.82rem;\">Publique vídeos e ganhe likes para entrar no rank!</div>';\n      return;\n    }\n    const medals = ['🥇','🥈','🥉','4️⃣','5️⃣'];\n    document.getElementById('rankList').innerHTML = data.rank.map((u, i) => {\n      const avHtml = u.avatarUrl\n        ? `<img src=\"${u.avatarUrl}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\" onerror=\"this.style.display='none';this.parentElement.textContent='${u.name.charAt(0).toUpperCase()}'\"/>`\n        : u.name.charAt(0).toUpperCase();\n      const goldClass = i===0?' rank-badge-gold':i===1?' rank-badge-silver':i===2?' rank-badge-bronze':'';\n      return `<div class=\"rank-card${goldClass}\" onclick=\"openProfile('${u.handle}')\">\n        <div class=\"rank-num\">${medals[i]}</div>\n        <div class=\"rank-av\" style=\"background:${u.color||'#0052e0'}\">${avHtml}</div>\n        <div class=\"rank-info\">\n          <div class=\"rank-name\">${u.name}${u.isVerified?'<span style=\"display:inline-flex;align-items:center;justify-content:center;width:12px;height:12px;background:#0052e0;clip-path:polygon(50% 0%,100% 50%,50% 100%,0% 50%);margin-left:3px;vertical-align:middle;\"><svg width=\"7\" height=\"7\" viewBox=\"0 0 24 24\" fill=\"white\"><path d=\"M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z\"/></svg></span>':''}</div>\n          <div class=\"rank-prize\" style=\"color:${u.color||'var(--blue)'};\">${u.label}</div>\n          <div class=\"rank-stats\">❤ ${formatNum(u.totalLikes)} · 👁 ${formatNum(u.totalViews)} · 👥 ${formatNum(u.followers)}</div>\n        </div>\n      </div>`;\n    }).join('');\n  } catch(e) {\n    document.getElementById('rankList').innerHTML = '<div style=\"text-align:center;padding:20px;color:var(--t3);font-size:.82rem;\">Rank indisponível no momento.</div>';\n  }\n}\n\n// ═══════════════════════════════════════\n// PREVIEW CARDS HOME\n// ═══════════════════════════════════════\nasync function buildPreviewCards() {\n  const scroll = document.getElementById('previewScroll');\n  scroll.innerHTML = '<div style=\"color:var(--t3);font-size:.78rem;padding:10px;\">Carregando canais…</div>';\n  try {\n    const res = await fetch('/api/videos/feed?limit=12');\n    if (!res.ok) throw new Error();\n    const data = await res.json();\n    if (!data.videos?.length) {\n      scroll.innerHTML = `<div style=\"width:100%;padding:28px 16px;text-align:center;background:var(--bg);border:1.5px dashed var(--border2);border-radius:14px;color:var(--t3);font-size:.82rem;\"><div style=\"font-size:2rem;margin-bottom:8px;\">🎬</div><strong style=\"color:var(--t2);display:block;margin-bottom:4px;\">Nenhum vídeo publicado ainda</strong>Seja o primeiro!</div>`;\n      return;\n    }\n    const seen = new Set();\n    const cards = data.videos.filter(v => {\n      const h = v.distributor?.handle || v.uploader?.handle;\n      if (!h || seen.has(h)) return false;\n      seen.add(h); return true;\n    }).slice(0, 12);\n\n    scroll.innerHTML = '';\n    cards.forEach(v => {\n      const presenter = v.distributor || v.uploader;\n      if (!presenter) return;\n      const card = document.createElement('div');\n      card.className = 'preview-card';\n      card.onclick = () => {\n        // Abre o feed direto no vídeo clicado\n        if (!feedVideos.find(x => x.id === v.id)) feedVideos.unshift(v);\n        document.getElementById('videoFeedPage').style.display === 'block'\n          ? (() => {\n              const el = document.querySelector('[data-vid-id=\"' + v.id + '\"]');\n              if (el) el.scrollIntoView({ behavior: 'instant', block: 'start' });\n            })()\n          : (() => {\n              openVideoFeed();\n              setTimeout(() => {\n                const tryS = (n) => {\n                  const el = document.querySelector('[data-vid-id=\"' + v.id + '\"]');\n                  if (el) el.scrollIntoView({ behavior: 'instant', block: 'start' });\n                  else if (n > 0) setTimeout(() => tryS(n-1), 100);\n                };\n                tryS(10);\n              }, 150);\n            })();\n      };\n      card.style.background = '#111';\n      const avHtml = presenter.avatarUrl\n        ? `<img src=\"${presenter.avatarUrl}\" style=\"position:absolute;inset:0;width:100%;height:100%;object-fit:cover;\"/>`\n        : '';\n      card.innerHTML = `\n        ${avHtml}\n        ${v.url ? `<video src=\"${v.url}\" muted preload=\"metadata\" playsinline style=\"position:absolute;inset:0;width:100%;height:100%;object-fit:cover;\" onloadedmetadata=\"this.currentTime=0.5\"></video>` : ''}\n        <div class=\"preview-card-overlay\"></div>\n        <div class=\"preview-card-play\"><svg width=\"16\" height=\"16\" viewBox=\"0 0 16 16\" fill=\"white\"><path d=\"M5 3l9 5-9 5V3z\"/></svg></div>\n        <div class=\"preview-card-info\">\n          <div class=\"preview-card-name\">${presenter.name}</div>\n          <div class=\"preview-card-views\">👁 ${formatNum(v.views||0)}</div>\n        </div>`;\n      scroll.appendChild(card);\n    });\n  } catch(e) {\n    scroll.innerHTML = '<div style=\"color:var(--t3);font-size:.78rem;padding:10px;\">Erro ao carregar canais.</div>';\n  }\n}\n\n// ═══════════════════════════════════════\n// AUTH\n// ═══════════════════════════════════════\nlet regAvUrl=null, regSelBadge=null, editAvUrl=null;\n\nfunction updateRegInit(){const v=document.getElementById('regName').value;const p=document.getElementById('regAvPrev');if(!regAvUrl)p.textContent=v.charAt(0).toUpperCase()||'C';}\nfunction selBadge(el){regSelBadge=el.dataset.b;document.querySelectorAll('#badgeSel .bo').forEach(e=>e.classList.remove('sel'));el.classList.add('sel');}\nfunction setAvCol(el,prevId){regAvUrl=null;const p=document.getElementById(prevId);p.style.background=el.dataset.c;document.querySelectorAll('.col-row .col-dot').forEach(d=>d.classList.remove('active'));el.classList.add('active');}\nfunction prevAvatar(inp,prevId){if(!inp.files[0])return;const r=new FileReader();r.onload=e=>{if(prevId==='regAvPrev')regAvUrl=e.target.result;else editAvUrl=e.target.result;const p=document.getElementById(prevId);p.innerHTML=`<img src=\"${e.target.result}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\"/>`;};r.readAsDataURL(inp.files[0]);}\nfunction updateEmailPreview(){const v=document.getElementById('regEmail').value.trim();const prev=document.getElementById('emailPreview');prev.textContent=v?v+'@capdrawn.com':'';}\n\nfunction createAccount() {\n  const name=document.getElementById('regName').value.trim();\n  const handle=document.getElementById('regHandle').value.trim().replace(/[^a-z0-9_]/gi,'').toLowerCase();\n  const emailRaw=document.getElementById('regEmail').value.trim();\n  const password=document.getElementById('regPass').value;\n  const desc=document.getElementById('regDesc').value.trim();\n  const errEl=document.getElementById('regErr');\n  errEl.style.display='none';\n  if(!name||!handle){errEl.textContent='⚠️ Preencha nome e @usuário!';errEl.style.display='block';return;}\n  if(!moderateText(name,'name')||!moderateText(handle,'name')){errEl.textContent='⚠️ Nome ou usuário bloqueado pela moderação.';errEl.style.display='block';return;}\n  if(!emailRaw){errEl.textContent='⚠️ Preencha o email!';errEl.style.display='block';return;}\n  if(!password||password.length<6){errEl.textContent='⚠️ Senha deve ter ao menos 6 caracteres!';errEl.style.display='block';return;}\n  const btn=document.getElementById('regBtn');\n  btn.disabled=true;btn.textContent='Criando...';\n  fetch('/api/auth/register',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name,handle,email:emailRaw,password})})\n  .then(r=>r.json()).then(data=>{\n    btn.disabled=false;btn.textContent='Criar conta →';\n    if(!data.ok){errEl.textContent='❌ '+data.error;errEl.style.display='block';return;}\n    APP.token=data.token;\n    const u=data.user;\n    APP.me={handle:u.handle,name:u.name,avatar:u.avatarUrl||null,email:u.email,vip:u.isVip,verified:u.isVerified,desc,area:regSelBadge,color:document.getElementById('regAvPrev').style.background||'#0052e0',isBot:false,videos:[]};\n    USERS[u.handle]=APP.me;\n    localStorage.setItem('cdToken',data.token);\n    localStorage.setItem('cdLoggedIn',u.handle);\n    regAvUrl=null;regSelBadge=null;\n    closeModal('regModal');\n    loginUser(u.handle);\n    toast('🎉 Conta criada! Bem-vindo, '+u.name+'!');\n  }).catch(()=>{btn.disabled=false;btn.textContent='Criar conta →';toast('❌ Erro de conexão');});\n}\n\nfunction openLogin(){openModal('loginModal');}\nfunction openRegister(){closeModal('loginModal');openModal('regModal');}\n\nfunction doLogin() {\n  const emailRaw=document.getElementById('liEmail').value.trim();\n  const password=document.getElementById('liPass').value;\n  const errEl=document.getElementById('loginErr');\n  errEl.style.display='none';\n  if(!emailRaw||!password){toast('⚠️ Preencha email e senha');return;}\n  const btn=document.getElementById('loginBtn');\n  btn.disabled=true;btn.textContent='Entrando...';\n  fetch('/api/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:emailRaw,password})})\n  .then(r=>r.json()).then(data=>{\n    btn.disabled=false;btn.textContent='Entrar →';\n    if(!data.ok){errEl.textContent='❌ '+data.error;errEl.style.display='block';return;}\n    APP.token=data.token;\n    const u=data.user;\n    APP.me={handle:u.handle,name:u.name,avatar:u.avatarUrl||null,email:u.email,vip:u.isVip,verified:u.isVerified,isBot:false,videos:[],color:'#0052e0'};\n    USERS[u.handle]=APP.me;\n    localStorage.setItem('cdToken',data.token);\n    localStorage.setItem('cdLoggedIn',u.handle);\n    closeModal('loginModal');\n    loginUser(u.handle);\n    toast('✅ Bem-vindo, '+u.name+'!');\n  }).catch(()=>{btn.disabled=false;btn.textContent='Entrar →';toast('❌ Erro de conexão');});\n}\n\nfunction loginUser(handle) {\n  APP.me = USERS[handle] || APP.me;\n  const u = APP.me;\n  document.getElementById('btnLogin').style.display='none';\n  document.getElementById('btnReg').style.display='none';\n  const nav=document.getElementById('navAv');\n  nav.style.display='flex';\n  nav.style.background=u.color||'#0052e0';\n  nav.textContent=u.name.charAt(0).toUpperCase();\n  if(u.avatar)nav.innerHTML=`<img src=\"${u.avatar}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\"/>`;\n  document.getElementById('loginPrompt').style.display='none';\n  document.getElementById('compose').classList.add('show');\n  checkFirstUse('comment','commentFirstUseBanner');\n  const av=document.getElementById('compAv');\n  av.style.background=u.color||'#0052e0';\n  av.textContent=u.name.charAt(0).toUpperCase();\n  if(u.avatar)av.innerHTML=`<img src=\"${u.avatar}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\"/>`;\n  if(u.vip)document.getElementById('scBtn').style.display='flex';\n  document.getElementById('fabBtn').style.display='flex';\n  renderHomeComments();\n  checkAdm();\n  checkAutoVerify();\n  // Load saved decoration\n  ownedDecorations = JSON.parse(localStorage.getItem('cdDecorations') || '[]');\n  activeDecoration = localStorage.getItem('cdActiveDecoration') || null;\n}\n\nfunction toggleAvMenu(e){e.stopPropagation();if(!APP.me){openLogin();return;}document.getElementById('avMenu').classList.toggle('open');}\nfunction closeAvMenu(){document.getElementById('avMenu').classList.remove('open');}\nfunction logout() {\n  APP.me=null;APP.token=null;\n  document.getElementById('btnLogin').style.display='';document.getElementById('btnReg').style.display='';\n  document.getElementById('navAv').style.display='none';\n  document.getElementById('loginPrompt').style.display='flex';\n  document.getElementById('compose').classList.remove('show');\n  document.getElementById('scBtn').style.display='none';\n  document.getElementById('fabBtn').style.display='none';\n  localStorage.removeItem('cdToken');localStorage.removeItem('cdLoggedIn');\n  closeModal('profileModal');\n  renderHomeComments();toast('Você saiu da conta.');\n}\n\nfunction openProfileModal() {\n  if(!APP.me){openLogin();return;}\n  const u=APP.me;\n  document.getElementById('editName').value=u.name;\n  document.getElementById('editDesc').value=u.desc||u.bio||'';\n  const p=document.getElementById('editAvPrev');\n  p.style.background=u.color||'#0052e0';p.textContent=u.name.charAt(0).toUpperCase();\n  if(u.avatar)p.innerHTML=`<img src=\"${u.avatar}\" style=\"width:100%;height:100%;object-fit:cover;border-radius:50%;\"/>`;\n  openModal('profileModal');\n}\n\nasync function saveProfile() {\n  if(!APP.me)return;\n  const name=document.getElementById('editName').value.trim()||APP.me.name;\n  const desc=document.getElementById('editDesc').value.trim();\n  const btn=document.querySelector('#profileModal .btn-main');\n  btn.disabled=true;btn.textContent='Salvando…';\n  try {\n    // Atualiza nome/bio no banco\n    await fetch(`/api/users/${APP.me.handle}`, {\n      method:'PUT',\n      headers:{'Content-Type':'application/json','Authorization':'Bearer '+APP.token},\n      body:JSON.stringify({name,desc})\n    });\n    // Se tiver nova foto, faz upload\n    if(editAvUrl) {\n      const res=await fetch('/api/auth/avatar',{\n        method:'POST',\n        headers:{'Content-Type':'application/json','Authorization':'Bearer '+APP.token},\n        body:JSON.stringify({avatarBase64:editAvUrl,name,bio:desc})\n      });\n      const data=await res.json();\n      if(data.ok&&data.user.avatarUrl) {\n        APP.me.avatar=data.user.avatarUrl;\n        USERS[APP.me.handle].avatarUrl=data.user.avatarUrl;\n      }\n    }\n    APP.me.name=name;APP.me.bio=APP.me.desc=desc;\n    USERS[APP.me.handle]={...USERS[APP.me.handle],...APP.me};\n    editAvUrl=null;\n    closeModal('profileModal');\n    loginUser(APP.me.handle);\n    toast('✅ Perfil atualizado!');\n  } catch(e){\n    toast('❌ Erro ao salvar perfil');\n  }\n  btn.disabled=false;btn.textContent='Salvar →';\n}\n\n// ═══════════════════════════════════════\n// VIP\n// ═══════════════════════════════════════\nfunction openVipModal(){openModal('vipModal');}\nfunction selPay(n){\n  document.getElementById('tikPayBox').style.display='none';\n  document.getElementById('ytSubBox').style.display='none';\n  document.querySelectorAll('.pay-opt').forEach(e=>e.classList.remove('selected'));\n  document.getElementById('po'+n).classList.add('selected');\n  if(n===1){document.getElementById('tikPayBox').style.display='block';document.getElementById('tikCode').textContent='CAPDRAWNN-'+Math.random().toString(36).slice(2,8).toUpperCase();}\n  if(n===2)document.getElementById('ytSubBox').style.display='block';\n}\nfunction copyCode(){const c=document.getElementById('tikCode').textContent;navigator.clipboard&&navigator.clipboard.writeText(c);toast('📋 Código copiado: '+c);}\nfunction confirmVipPayment(){if(!APP.me){openLogin();return;}APP.me.vip=true;APP.me.vipTier='pro';closeModal('vipModal');document.getElementById('vipStatusTxt').textContent='VIP Pro ativo ✓';document.getElementById('scBtn').style.display='flex';toast('⭐ VIP Pro ativado!');}\nfunction confirmVipYT(){if(!APP.me){openLogin();return;}APP.me.vip=true;APP.me.vipTier='ultra';APP.me.verified=true;closeModal('vipModal');document.getElementById('vipStatusTxt').textContent='VIP Ultra ativo ✓';document.getElementById('scBtn').style.display='flex';toast('⭐ VIP Ultra ativado!');}\n\nfunction openSuperChat(){if(!APP.me?.vip){toast('⭐ Super Chat é exclusivo VIP!');return;}openModal('scModal');}\nfunction sendSuperChat(){\n  if(!APP.me)return;\n  const msg=document.getElementById('scMsg').value.trim(),val=parseInt(document.getElementById('scVal').value);\n  if(!msg){toast('Digite uma mensagem!');return;}\n  const colors={5:'sc-3',20:'sc-2',50:'sc-1'};\n  const cls=colors[val]||'sc-3';\n  const sc=document.getElementById('superchats');sc.classList.add('show');\n  const u=APP.me;\n  sc.innerHTML+=`<div class=\"sc-item ${cls}\"><div class=\"sc-av\">${u.name.charAt(0)}</div><div><strong style=\"font-size:.76rem;\">${u.name}</strong><div class=\"sc-msg\">${msg}</div></div><div class=\"sc-val\">R$${val}</div></div>`;\n  closeModal('scModal');toast('💛 Super Chat enviado!');\n  HOME_COMMENTS.unshift({id:nextLocalId++,handle:u.handle,text:`💛 Super Chat R$${val}: ${msg}`,time:'agora',likes:0,likedBy:[],pinned:false});\n  renderHomeComments();\n  setTimeout(()=>{const items=sc.querySelectorAll('.sc-item');if(items.length>5)items[0].remove();},15000);\n}\n\n// ═══════════════════════════════════════\n// UPLOAD DE VÍDEO\n// ═══════════════════════════════════════\nlet currentVideoFile = null;\nlet videoAnalysisOk = false;\n\nfunction openUploadVideo(){\n  if(!APP.me){openLogin();return;}\n  if(isInAppBrowser()){closePublishMenu();openInBrowserInstructions();return;}\n  closePublishMenu();\n  clearVideo();\n  document.getElementById('uploadFields').style.display='none';\n  document.getElementById('uploadDistSection').style.display='none';\n  document.getElementById('uploadSubmitBtn').style.display='none';\n  document.getElementById('uploadAnalysis').style.display='none';\n  document.getElementById('uploadDrop').style.display='block';\n  selectedDist='profile';\n  selDist('profile');\n  videoPrivacy = 'public';\n  selPrivacy('public');\n  openModal('uploadModal');\n  checkFirstUse('upload', 'uploadFirstUseBanner');\n}\n\nfunction onDragOver(e){e.preventDefault();document.getElementById('uploadDrop').classList.add('drag');}\nfunction onDragLeave(e){document.getElementById('uploadDrop').classList.remove('drag');}\nfunction onDrop(e){e.preventDefault();document.getElementById('uploadDrop').classList.remove('drag');const f=e.dataTransfer.files[0];if(f&&f.type.startsWith('video/'))handleVideoFile(f);}\n\nfunction handleVideoFile(file){\n  if(!file)return;\n  if(file.size>200*1024*1024){toast('⚠️ Vídeo muito grande! Máx. 200MB.');return;}\n  currentVideoFile=file;\n  const url=URL.createObjectURL(file);\n  const preview=document.getElementById('uploadPreview');\n  const vidEl=document.getElementById('uploadVidEl');\n  vidEl.src=url;preview.style.display='block';\n  document.getElementById('uploadDrop').style.display='none';\n  vidEl.play().catch(()=>{});\n  analyzeVideoContent(file);\n}\n\nasync function analyzeVideoContent(file){\n  const analysisEl=document.getElementById('uploadAnalysis');\n  analysisEl.style.display='block';\n  analysisEl.className='upload-analysis';\n  analysisEl.innerHTML='⏳ Analisando conteúdo do vídeo…';\n  videoAnalysisOk=false;\n  document.getElementById('uploadSubmitBtn').style.display='none';\n  await new Promise(r=>setTimeout(r,1500));\n  const name=file.name.toLowerCase();\n  const badWords=['porn','sex','nude','nsfw','gore','violence','18+','xxx'];\n  const hasBadWord=badWords.some(w=>name.includes(w));\n  if(hasBadWord){\n    analysisEl.className='upload-analysis error';\n    analysisEl.innerHTML='🚫 <strong>Upload bloqueado.</strong> Conteúdo possivelmente impróprio.';\n    videoAnalysisOk=false;\n  } else {\n    analysisEl.className='upload-analysis ok';\n    analysisEl.innerHTML='✅ <strong>Aprovado!</strong> Escolha como publicar.';\n    videoAnalysisOk=true;\n    document.getElementById('uploadFields').style.display='flex';\n    document.getElementById('uploadDistSection').style.display='block';\n    document.getElementById('uploadSubmitBtn').style.display='inline-flex';\n  }\n}\n\nfunction clearVideo(){\n  currentVideoFile=null;videoAnalysisOk=false;\n  const v=document.getElementById('uploadVidEl');v.src='';v.pause();\n  document.getElementById('uploadPreview').style.display='none';\n  document.getElementById('uploadDrop').style.display='block';\n  document.getElementById('uploadAnalysis').style.display='none';\n  document.getElementById('uploadFields').style.display='none';\n  document.getElementById('uploadDistSection').style.display='none';\n  document.getElementById('uploadSubmitBtn').style.display='none';\n}\n\nfunction selDist(type){\n  selectedDist=type;\n  ['profile','bots','both'].forEach(t=>{\n    const el=document.getElementById('dopt'+t.charAt(0).toUpperCase()+t.slice(1));\n    if(el)el.classList.toggle('sel',t===type);\n  });\n  // Mostra seletor de bot quando modo bot/ambos\n  const botPicker=document.getElementById('botPickerDiv');\n  if(botPicker) botPicker.classList.toggle('show', type==='bots'||type==='both');\n}\n\nasync function submitVideo(){\n  if(!APP.me||!currentVideoFile||!videoAnalysisOk){toast('⚠️ Selecione um vídeo válido!');return;}\n  const btn=document.getElementById('uploadSubmitBtn');\n  btn.disabled=true;btn.textContent='⏳ Enviando...';\n  const caption=document.getElementById('vidCaption').value.trim()||'🎥 Vídeo da comunidade';\n  if(!moderateText(caption,'caption')) { btn.disabled=false;btn.textContent='Publicar →'; return; }\n  // API moderation check\n  toast('⏳ Verificando conteúdo…');\n  const apiOk = await moderateViaAPI(caption);\n  if(!apiOk) { toast('🚫 Conteúdo bloqueado pela análise automática.'); btn.disabled=false;btn.textContent='Publicar →'; return; }\n  const distributed=selectedDist==='bots'||selectedDist==='both';\n  const botHandle=document.getElementById('botPickerSelect').value || (distributed && botList.length ? getRandomBot()?.handle : null);\n  try{\n    const fd=new FormData();\n    fd.append('video',currentVideoFile);\n    fd.append('caption',caption);\n    fd.append('privacy',videoPrivacy);\n    fd.append('distributed',String(distributed));\n    if(botHandle) fd.append('botHandle',botHandle);\n    const res=await fetch('/api/videos/upload',{method:'POST',headers:APP.token?{'Authorization':'Bearer '+APP.token}:{},body:fd});\n    const data=await res.json();\n    if(!data.ok)throw new Error(data.error||'Erro no servidor');\n    closeModal('uploadModal');clearVideo();\n    btn.disabled=false;btn.textContent='Publicar →';\n    buildPreviewCards();loadRank();\n    const botName=botHandle&&USERS[botHandle]?USERS[botHandle].name:botHandle;\n    const msgs={\n      profile:'✅ Vídeo publicado no seu perfil!',\n      bots:`🤖 Vídeo enviado para @${botName||'bot'} distribuir!`,\n      both:`🚀 Publicado e distribuído por @${botName||'bot'}!`\n    };\n    toast(msgs[selectedDist]||'✅ Publicado!');\n    // Dispara fakeviews para o vídeo novo\n    setTimeout(()=>fetch('/api/videos/fakeviews',{method:'POST'}).catch(()=>{}),2000);\n  }catch(e){\n    console.error('submitVideo:',e);\n    toast('❌ Erro no upload: '+e.message);\n    btn.disabled=false;btn.textContent='Publicar →';\n  }\n}\n\n// ═══════════════════════════════════════\n// CANAL\n// ═══════════════════════════════════════\nfunction openCreateChannel(){if(!APP.me){closePublishMenu();openLogin();return;}closePublishMenu();document.getElementById('chanName').value='';document.getElementById('chanEmail').value='';document.getElementById('chanPass').value='';updateChanPreview();openModal('channelModal');}\nfunction updateChanPreview(){const email=document.getElementById('chanEmail').value.trim().toLowerCase().replace(/[^a-z0-9._]/g,'');const full=email?`${email}@capdrawn.com`:'email@capdrawn.com';document.getElementById('chanEmailFinal').textContent=full;document.getElementById('chanEmailPreview').textContent=email?`✓ Seu email: ${full}`:'Preencha o nome do email acima';}\nfunction createChannel(){\n  const name=document.getElementById('chanName').value.trim();\n  const email=document.getElementById('chanEmail').value.trim().toLowerCase().replace(/[^a-z0-9._]/g,'');\n  const pass=document.getElementById('chanPass').value.trim();\n  if(!name){toast('⚠️ Digite o nome do canal!');return;}\n  if(!moderateText(name,'name')){return;}\n  if(!email){toast('⚠️ Digite o email!');return;}\n  if(pass.length<6){toast('⚠️ Senha deve ter ao menos 6 caracteres!');return;}\n  const fullEmail=`${email}@capdrawn.com`;\n  if(APP.me){APP.me.channelEmail=fullEmail;}\n  // Salva no banco via API\n  fetch('/api/channels',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({handle:APP.me?.handle,name,email:fullEmail})}).catch(()=>{});\n  closeModal('channelModal');\n  toast(`📡 Canal criado! Email: ${fullEmail}`);\n}\n\n// ═══════════════════════════════════════\n// DENÚNCIA\n// ═══════════════════════════════════════\nfunction openReportModal(vidId){currentReportVidId=vidId;reportType=null;copyrightType=null;document.querySelectorAll('.report-opt').forEach(o=>o.classList.remove('sel'));document.getElementById('reportCopyrightSub').classList.remove('show');document.getElementById('reportConfirmBox').style.display='none';openModal('reportModal');}\nfunction selReport(type){reportType=type;copyrightType=null;document.querySelectorAll('.report-opt').forEach(o=>o.classList.remove('sel'));document.getElementById('ropt1').classList.toggle('sel',type==='inappropriate');document.getElementById('ropt2').classList.toggle('sel',type==='copyright');const sub=document.getElementById('reportCopyrightSub');sub.classList.toggle('show',type==='copyright');const box=document.getElementById('reportConfirmBox');if(type==='inappropriate'){box.style.display='block';document.getElementById('reportConfirmTxt').textContent='Este vídeo será revisado pela equipe em até 24h.';}else{box.style.display='none';}}\nfunction selCopyrightType(type){copyrightType=type;['Owner','Third'].forEach(t=>{document.getElementById('rsub'+t).classList.toggle('sel',type===t.toLowerCase());document.getElementById('rsub'+t+'Dot').style.background=type===t.toLowerCase()?'var(--blue)':'';document.getElementById('rsub'+t+'Dot').style.borderColor=type===t.toLowerCase()?'var(--blue)':'var(--border2)';});const box=document.getElementById('reportConfirmBox');box.style.display='block';document.getElementById('reportConfirmTxt').textContent=type==='owner'?'Como detentor, o vídeo será removido imediatamente.':'Nossa equipe avaliará em 48h.';}\nfunction submitReport(){\n  if(!reportType){toast('⚠️ Selecione o tipo!');return;}\n  if(reportType==='copyright'&&!copyrightType){toast('⚠️ Selecione sua relação com o conteúdo!');return;}\n  closeModal('reportModal');\n\n  const videoId = currentReportVidId;\n  currentReportVidId = null;\n\n  const msgs={'inappropriate':'🚩 Denúncia enviada! Revisaremos em 24h.','copyright':'📋 Denúncia de direitos enviada!'};\n  toast(msgs[reportType]||'📋 Denúncia enviada!');\n\n  // Chama a API de denúncia\n  fetch('/api/report', {\n    method: 'POST',\n    headers: {'Content-Type':'application/json'},\n    body: JSON.stringify({\n      videoId,\n      type: reportType,\n      subtype: copyrightType || null,\n      reporterId: APP.me?.id || null\n    })\n  }).then(r => r.json()).then(data => {\n    // Se for copyright/owner → vídeo foi removido, tira do feed também\n    if(data.ok && reportType === 'copyright' && copyrightType === 'owner') {\n      feedVideos = feedVideos.filter(v => v.id !== videoId);\n      const el = document.querySelector(`.vid-snap-item[data-vid-id=\"${videoId}\"]`);\n      if(el) el.remove();\n      toast('🗑 Vídeo removido com sucesso!');\n    }\n  }).catch(()=>{});\n}\n\n// ═══════════════════════════════════════\n// PUBLISH MENU\n// ═══════════════════════════════════════\nfunction openPublishMenu(){if(!APP.me){openLogin();return;}publishMenuOpen=!publishMenuOpen;document.getElementById('publishMenu').style.display=publishMenuOpen?'block':'none';const fab=document.getElementById('fabBtn');if(fab)fab.style.transform=publishMenuOpen?'rotate(45deg)':'rotate(0)';}\nfunction closePublishMenu(){publishMenuOpen=false;document.getElementById('publishMenu').style.display='none';const fab=document.getElementById('fabBtn');if(fab)fab.style.transform='rotate(0)';}\n\n// ═══════════════════════════════════════\n// NAV\n// ═══════════════════════════════════════\nfunction setActiveNav(id){document.querySelectorAll('.bnav-btn').forEach(b=>b.classList.remove('active'));const el=document.getElementById(id);if(el)el.classList.add('active');}\nfunction goHome(){closeVideoFeed();if(document.getElementById('profilePage').style.display==='block')closeProfile();if(document.getElementById('settingsPage').classList.contains('show'))closeSettings();setActiveNav('bnavHome');window.scrollTo({top:0,behavior:'smooth'});}\nfunction openSettings(){document.getElementById('settingsPage').classList.add('show');document.body.style.overflow='hidden';}\nfunction closeSettings(){document.getElementById('settingsPage').classList.remove('show');document.body.style.overflow='';}\n\n// ═══════════════════════════════════════\n// MODAIS\n// ═══════════════════════════════════════\nfunction openModal(id){document.getElementById(id).classList.add('show');}\nfunction closeModal(id){document.getElementById(id).classList.remove('show');}\n\n// ═══════════════════════════════════════\n// UTILS\n// ═══════════════════════════════════════\nfunction formatNum(n){\n  n=Number(n)||0;\n  if(n>=1000000000)return(n/1000000000).toFixed(1).replace('.0','')+'B';\n  if(n>=1000000)return(n/1000000).toFixed(1).replace('.0','')+'M';\n  if(n>=1000)return(n/1000).toFixed(1).replace('.0','')+'K';\n  return String(n);\n}\n\nfunction formatTimeAgo(dateStr) {\n  if (!dateStr) return 'agora';\n  const d = new Date(dateStr);\n  const diff = (Date.now() - d.getTime()) / 1000;\n  if (diff < 60) return 'agora';\n  if (diff < 3600) return Math.floor(diff/60)+'min atrás';\n  if (diff < 86400) return Math.floor(diff/3600)+'h atrás';\n  return Math.floor(diff/86400)+'d atrás';\n}\n\nlet toastTimer;\nfunction toast(msg){const el=document.getElementById('toast');el.textContent=msg;el.classList.add('show');clearTimeout(toastTimer);toastTimer=setTimeout(()=>el.classList.remove('show'),2800);}\n\n// ═══════════════════════════════════════\n// PERSISTÊNCIA LOCAL (chat da home)\n// ═══════════════════════════════════════\nfunction saveHomeCommentsLocal(){try{localStorage.setItem('cdHomeComments',JSON.stringify(HOME_COMMENTS.slice(0,100)));}catch(e){}}\n\n\n// ═══════════════════════════════════════\n// CONTENT MODERATION\n// ═══════════════════════════════════════\nconst BAD_WORDS = [\n  'puta','porra','caralho','merda','cuzão','viado','fdp','vsf','buceta','pau','piroca',\n  'bosta','idiota','imbecil','babaca','lixo','canalha','maldito','desgraça','cretino',\n  'vagabundo','vagabunda','otário','piranha','sapatão','traveco','retardado',\n  'fuck','shit','bitch','ass','cunt','dick','pussy','nigger','faggot','whore',\n];\n\n// Normaliza texto: remove símbolos ao redor de letras e converte leetspeak\nfunction normalizeText(text) {\n  let t = text.toLowerCase();\n  // Remove símbolos usados para disfarçar letras\n  t = t.replace(/[@4]/g,'a').replace(/[3€]/g,'e').replace(/[1!|]/g,'i')\n        .replace(/[0°]/g,'o').replace(/[5$]/g,'s').replace(/[7]/g,'t')\n        .replace(/[ck]/g,'c').replace(/[ph]/g,'f');\n  // Remove caracteres não alfanuméricos entre letras (ex: ass@lto -> assalto)\n  t = t.replace(/[^a-z0-9\\s]/g,'');\n  return t;\n}\n\nfunction containsBadWord(text) {\n  if (!text) return false;\n  const norm = normalizeText(text);\n  return BAD_WORDS.some(w => norm.includes(w));\n}\n\nfunction moderateText(text, context) {\n  if (containsBadWord(text)) {\n    const msgs = {\n      comment: '🚫 Comentário bloqueado pela moderação automática.',\n      name: '🚫 Nome não permitido pela moderação automática.',\n      caption: '🚫 Legenda bloqueada pela moderação automática.',\n    };\n    toast(msgs[context] || '🚫 Conteúdo bloqueado pela moderação.');\n    return false;\n  }\n  return true;\n}\n\n// Moderação via API gratuita (Perspective-like via Hugging Face)\nasync function moderateViaAPI(text) {\n  try {\n    const res = await fetch('https://api-inference.huggingface.co/models/unitary/toxic-bert', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ inputs: text }),\n    });\n    if (!res.ok) return true; // fallback: permite se API falhar\n    const data = await res.json();\n    if (!Array.isArray(data) || !data[0]) return true;\n    const toxic = data[0].find(r => r.label === 'toxic');\n    return !(toxic && toxic.score > 0.75); // bloqueia se score > 75%\n  } catch(e) { return true; } // fallback: permite se sem conexão\n}\n\n// ═══════════════════════════════════════\n// ADM SYSTEM\n// ═══════════════════════════════════════\nconst ADM_HANDLE = 'capdrawnOFC';\nconst ADM_PASS = '7723';\nlet isAdm = false;\nlet maintenanceMode = false;\nlet maintenanceMsg = '';\nlet maintenanceUntil = null;\n\nfunction checkAdm() {\n  isAdm = APP.me?.handle?.toLowerCase() === ADM_HANDLE.toLowerCase();\n  const bar = document.getElementById('admBar');\n  const admSet = document.getElementById('admSettingsGroup');\n  if (isAdm) {\n    if (admSet) admSet.style.display = 'block';\n  } else {\n    bar.classList.remove('show');\n    if (admSet) admSet.style.display = 'none';\n  }\n  // Chip só aparece quando manutenção ativa\n  if (maintenanceMode && isAdm) bar.classList.add('show');\n  else if (!maintenanceMode) bar.classList.remove('show');\n}\n\nfunction promptAdmLogin() {\n  const pass = prompt('Senha ADM:');\n  if (!pass) return;\n  if (pass === ADM_PASS && APP.me?.handle?.toLowerCase() === ADM_HANDLE.toLowerCase()) {\n    isAdm = true;\n    checkAdm();\n    document.getElementById('maintenancePage').classList.remove('show');\n    toast('🛡️ Modo ADM ativado!');\n  } else {\n    toast('❌ Senha incorreta.');\n  }\n}\n\nfunction openAdmPanel() {\n  const inp = document.getElementById('admMaintMsgInp');\n  if (inp) inp.value = maintenanceMsg;\n  const btn = document.getElementById('admMaintBtnTxt');\n  if (btn) btn.textContent = maintenanceMode ? '✅ Desativar Manutenção' : '🔧 Ativar Manutenção';\n  openModal('admPanelModal');\n}\n\nfunction toggleMaintenance() {\n  if (!isAdm) return;\n  maintenanceMode = !maintenanceMode;\n  const msgInp = document.getElementById('admMaintMsgInp');\n  const dateInp = document.getElementById('admMaintDate');\n  if (msgInp && msgInp.value.trim()) maintenanceMsg = msgInp.value.trim();\n  if (dateInp && dateInp.value) maintenanceUntil = new Date(dateInp.value);\n  else maintenanceUntil = null;\n  applyMaintenanceState();\n  if(APP.token){fetch('/api/maintenance',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+APP.token},body:JSON.stringify({active:maintenanceMode,message:maintenanceMsg,until:maintenanceUntil?.toISOString()||null})}).catch(()=>{});}\n  closeModal('admPanelModal');\n  toast(maintenanceMode ? '🔧 Manutenção ativada!' : '✅ Plataforma online!');\n}\n\nfunction applyMaintenanceState() {\n  const page = document.getElementById('maintenancePage');\n  const bar = document.getElementById('admBar');\n  const btn = document.getElementById('maintToggleBtn');\n  const statusDot = document.getElementById('admStatusDot');\n  const statusTxt = document.getElementById('admStatusTxt');\n  const admStatus = document.getElementById('admMaintStatus');\n  const admBtnTxt = document.getElementById('admMaintBtnTxt');\n  if (maintenanceMode && !isAdm) {\n    page.classList.add('show');\n  } else {\n    page.classList.remove('show');\n  }\n  // Chip flutuante: visível apenas quando manutenção ativa (para o ADM)\n  if (bar && isAdm) {\n    if (maintenanceMode) bar.classList.add('show');\n    else bar.classList.remove('show');\n  }\n  if (maintenanceMsg) document.getElementById('maintMsg').textContent = maintenanceMsg;\n  const mSub = document.getElementById('maintSettingsSub');\n  if (mSub) mSub.textContent = maintenanceMode ? '\xe2\x9a\xa0\xef\xb8\x8f Manuten\xc3\xa7\xc3\xa3o ativa' : 'Plataforma online';\n  if (maintenanceUntil) {\n    document.getElementById('maintDate').textContent = 'Previsão: ' + maintenanceUntil.toLocaleString('pt-BR');\n  } else {\n    document.getElementById('maintDate').textContent = '';\n  }\n  if (btn) btn.textContent = maintenanceMode ? '✅ Desativar Manutenção' : '🔧 Ativar Manutenção';\n  if (statusDot) statusDot.style.background = maintenanceMode ? '#f03050' : 'var(--green)';\n  if (statusTxt) statusTxt.textContent = maintenanceMode ? 'Manutenção ativa' : 'Online';\n  if (admStatus) admStatus.textContent = maintenanceMode ? '⚠️ Manutenção ativa' : 'Plataforma online';\n  if (admBtnTxt) admBtnTxt.textContent = maintenanceMode ? '✅ Desativar Manutenção' : '🔧 Ativar Manutenção';\n}\n\n// ═══════════════════════════════════════\n// STORE SYSTEM\n// ═══════════════════════════════════════\nconst STORE_ITEMS = [\n  { id:'gold',    icon:'✨', name:'Nome Dourado',    desc:'Estilo dourado elegante no seu nome',   class:'name-gold',    req:'vip',      reqLabel:'VIP Pro' },\n  { id:'ice',     icon:'❄️', name:'Nome Gelo',       desc:'Visual frio e estiloso — tema suspense', class:'name-ice',     req:'free',     reqLabel:'Grátis' },\n];\n\nlet ownedDecorations = JSON.parse(localStorage.getItem('cdDecorations') || '[]');\nlet activeDecoration = localStorage.getItem('cdActiveDecoration') || null;\n\nfunction openStore() {\n  if (!APP.me) { openLogin(); return; }\n  renderStore();\n  openModal('storeModal');\n}\n\nfunction renderStore() {\n  const grid = document.getElementById('storeGrid');\n  if (!grid) return;\n  grid.innerHTML = STORE_ITEMS.map(item => {\n    const owned = ownedDecorations.includes(item.id) || (isAdm);\n    const active = activeDecoration === item.id;\n    const canUnlock = item.req === 'free' || (item.req === 'vip' && APP.me?.vip) || (item.req === 'verified' && APP.me?.verified) || isAdm;\n    return `<div class=\"store-item${owned?' owned':canUnlock?'':' locked'}\" onclick=\"handleStoreItem('${item.id}')\">\n      <span class=\"store-item-badge ${item.req==='free'?'free':item.req==='vip'?'vip':'verify'}\">${item.reqLabel}</span>\n      <div class=\"store-item-icon\">${item.icon}</div>\n      <div class=\"store-item-name ${active?item.class:''}\">${item.name}</div>\n      <div class=\"store-item-desc\">${item.desc}</div>\n      ${active ? '<div style=\"margin-top:6px;font-size:.65rem;font-weight:700;color:var(--green);\">✓ Ativo</div>' : owned ? '<div style=\"margin-top:6px;font-size:.65rem;font-weight:700;color:var(--blue);\">Equipar</div>' : ''}\n    </div>`;\n  }).join('');\n}\n\nfunction handleStoreItem(id) {\n  if (!APP.me) { openLogin(); return; }\n  const item = STORE_ITEMS.find(i => i.id === id);\n  if (!item) return;\n  const canUnlock = item.req === 'free' || (item.req === 'vip' && APP.me?.vip) || (item.req === 'verified' && APP.me?.verified) || isAdm;\n  if (!canUnlock) { toast('🔒 Requisito: ' + item.reqLabel); return; }\n  if (!ownedDecorations.includes(id)) { ownedDecorations.push(id); localStorage.setItem('cdDecorations', JSON.stringify(ownedDecorations)); }\n  if (activeDecoration === id) {\n    activeDecoration = null; // toggle off\n  } else {\n    activeDecoration = id;\n  }\n  localStorage.setItem('cdActiveDecoration', activeDecoration || '');\n  renderStore();\n  toast(activeDecoration ? '✨ Decoração aplicada!' : '❌ Decoração removida.');\n}\n\nfunction getDecoratedName(name) {\n  if (!activeDecoration) return name;\n  const item = STORE_ITEMS.find(i => i.id === activeDecoration);\n  if (!item) return name;\n  return `<span class=\"${item.class}\">${name}</span>`;\n}\n\n// ═══════════════════════════════════════\n// FIRST USE ALERTS\n// ═══════════════════════════════════════\nfunction checkFirstUse(key, bannerId) {\n  const done = localStorage.getItem('cdFirstUse_' + key);\n  if (!done) {\n    const el = document.getElementById(bannerId);\n    if (el) el.classList.add('show');\n  }\n}\n\nfunction dismissFirstUse(key) {\n  localStorage.setItem('cdFirstUse_' + key, '1');\n  const map = { comment: 'commentFirstUseBanner', upload: 'uploadFirstUseBanner' };\n  const el = document.getElementById(map[key]);\n  if (el) el.classList.remove('show');\n}\n\n// ═══════════════════════════════════════\n// PRIVACY\n// ═══════════════════════════════════════\nlet videoPrivacy = 'public';\nfunction selPrivacy(p) {\n  videoPrivacy = p;\n  document.getElementById('privPublic').classList.toggle('sel', p==='public');\n  document.getElementById('privPrivate').classList.toggle('sel', p==='private');\n}\n\n// ═══════════════════════════════════════\n// AUTO-VERIFY AT 10K\n// ═══════════════════════════════════════\nfunction checkAutoVerify() {\n  if (!APP.me) return;\n  const u = USERS[APP.me.handle];\n  if (u && u.followers >= 10000 && !APP.me.verified) {\n    APP.me.verified = true;\n    if (USERS[APP.me.handle]) USERS[APP.me.handle].isVerified = true;\n    toast('🎉 Parabéns! Você atingiu 10K seguidores e ganhou o selo verificado!');\n  }\n}\n\n// ═══════════════════════════════════════\n// PIN COMMENT IN VIDEO\n// ═══════════════════════════════════════\nlet pinnedVidComments = JSON.parse(localStorage.getItem('cdPinnedVidComments') || '{}');\n\nfunction pinVidComment(videoId, commentId) {\n  if (!pinnedVidComments[videoId]) pinnedVidComments[videoId] = null;\n  pinnedVidComments[videoId] = pinnedVidComments[videoId] === commentId ? null : commentId;\n  localStorage.setItem('cdPinnedVidComments', JSON.stringify(pinnedVidComments));\n  openVidComments(videoId); // refresh\n  toast(pinnedVidComments[videoId] ? '📌 Comentário fixado!' : '📌 Comentário desafixado!');\n}\n\n\n// ═══════════════════════════════════════\n// INIT\n// ═══════════════════════════════════════\ndocument.addEventListener('DOMContentLoaded', async () => {  // Verifica manutenção persistida\n  fetch('/api/maintenance').then(r=>r.ok?r.json():null).then(d=>{if(d&&d.active){maintenanceMode=true;maintenanceMsg=d.message||'';maintenanceUntil=d.until?new Date(d.until):null;applyMaintenanceState();}}).catch(()=>{})\n  // Carrega comentários do chat da home\n  try {\n    const saved = JSON.parse(localStorage.getItem('cdHomeComments') || '[]');\n    if (saved.length) {\n      HOME_COMMENTS.push(...saved);\n      nextLocalId = Math.max(...saved.map(c=>c.id||0), nextLocalId) + 1;\n    }\n  } catch(e) {}\n\n  // Carrega bots do banco\n  await loadBots();\n\n  // Adiciona comentários iniciais dos bots no chat da home (se vazio)\n  if (!HOME_COMMENTS.length && botList.length) {\n    const initial = [\n      'Bem-vindos ao CapDrawn MemeShorts 💀 Feed da comunidade ativo.',\n      'Feed operacional. Poste vídeos e a rede distribui.',\n      'Sistema funcionando 100% — conteúdo chegando.',\n      'Publique seu primeiro vídeo e veja os números subirem!',\n      'Rede de distribuição pronta. Escolha um bot para distribuir seu conteúdo.',\n    ];\n    botList.slice(0, 5).forEach((b, i) => {\n      HOME_COMMENTS.push({\n        id: nextLocalId++, handle: b.handle, text: initial[i] || BOT_COMMENTS_HOME[i],\n        time: `${(i+1)*2}h atrás`, likes: Math.floor(Math.random()*40)+5, likedBy: [], pinned: i===0,\n        isBot: true,\n      });\n    });\n    saveHomeCommentsLocal();\n  }\n\n  renderHomeComments();\n\n  // Auto-login\n  const savedToken = localStorage.getItem('cdToken');\n  const loggedIn = localStorage.getItem('cdLoggedIn');\n  if (savedToken && loggedIn) {\n    fetch('/api/auth/me', {headers:{'Authorization':'Bearer '+savedToken}})\n    .then(r=>r.json()).then(data=>{\n      if(data.ok&&data.user){\n        APP.token=savedToken;\n        const u=data.user;\n        APP.me={handle:u.handle,name:u.name,avatar:u.avatarUrl||null,email:u.email,vip:u.isVip,verified:u.isVerified,isBot:false,videos:[],color:'#0052e0'};\n        USERS[u.handle]=APP.me;\n        loginUser(u.handle);\n      } else {\n        localStorage.removeItem('cdToken');localStorage.removeItem('cdLoggedIn');\n      }\n    }).catch(()=>{});\n  }\n\n  // Carrega preview cards, rank e dispara fakeviews\n  buildPreviewCards();\n  loadRank();\n  fetch('/api/videos/fakeviews',{method:'POST'}).catch(()=>{});\n\n  // Seed de bots se necessário (roda em background, não bloqueia)\n  fetch('/api/admin/seed-bots').catch(()=>{});\n  // Garante que conta ADM CapDrawnOFC existe\n  fetch('/api/auth/register', {    method:'POST',headers:{'Content-Type':'application/json'},\n    body:JSON.stringify({name:'CapDrawn Oficial',handle:ADM_HANDLE,email:'capdrawn@capdrawn.com',password:ADM_PASS})\n  }).then(r=>r.json()).then(data=>{\n    if(data.ok && data.token){\n      fetch('/api/admin/setup-official',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+data.token}}).catch(()=>{});\n    }\n  }).catch(()=>{});\n\n  // ── URL pública de Shorts: mostra splash antes de abrir ──\n  if (location.hash === '#shorts') {\n    document.getElementById('shortsSplash').classList.add('show');\n  }\n});\n\ndocument.addEventListener('click', e => {\n  if(!e.target.closest('#navAv')&&!e.target.closest('#avMenu'))closeAvMenu();\n  if(publishMenuOpen&&!e.target.closest('#publishMenu')&&!e.target.closest('#fabBtn'))closePublishMenu();\n  if(!e.target.closest('#compose')&&!e.target.closest('#mentDrop'))hideMentDrop();\n  if(e.target.classList.contains('overlay'))closeModal(e.target.id);\n  if(!e.target.closest('#videoCommentsModal')&&e.target.classList.contains('overlay'))hideVcMentDrop?.();\n});\n</script>\n</body>\n</html>\n";

export default HTML;
